import React, { useState, useEffect, useRef, useCallback } from "react";

// ------------------------------
// SECTION: TYPES & DB CONFIG
// ------------------------------
const DB_NAME = "WitnessLoopDB";
const STORE_NAME = "rolling_buffer";
const MAX_CHUNKS = 10; // 10 chunks * 30s = 5 minutes
const recorderSliceIntervals = new WeakMap<MediaRecorder, number>();

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve) => {
    const req = indexedDB.open(DB_NAME, 3);
    req.onupgradeneeded = (e: IDBVersionChangeEvent) => {
      const db = (e.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: "id" });
      }
    };
    req.onsuccess = () => resolve(req.result);
  });
};

// ------------------------------
// SECTION: MAIN COMPONENT
// ------------------------------
export default function WitnessLoopRecording() {
  const [isLooping, setIsLooping] = useState(false);
  const [bufferSec, setBufferSec] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const recorderRef = useRef<MediaRecorder | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunkIds = useRef<string[]>([]);
  const tickerRef = useRef<number | null>(null);

  // 1. Storage Logic
  const pushToBuffer = async (blob: Blob) => {
    const db = await openDB();
    const id = `chunk_${Date.now()}`;

    const tx = db.transaction(STORE_NAME, "readwrite");
    tx.objectStore(STORE_NAME).add({ id, blob, ts: Date.now() });

    chunkIds.current.push(id);

    // Maintain 5-minute window
    if (chunkIds.current.length > MAX_CHUNKS) {
      const oldestId = chunkIds.current.shift();
      if (oldestId) {
        const delTx = db.transaction(STORE_NAME, "readwrite");
        delTx.objectStore(STORE_NAME).delete(oldestId);
      }
    }
  };

  // 2. Start Recording
  const startLoop = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      streamRef.current = stream;

      const recorder = new MediaRecorder(stream, { mimeType: "video/webm" });
      recorderRef.current = recorder;

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) pushToBuffer(e.data);
      };

      // We use a manual slice strategy for better browser compatibility
      recorder.start();
      const sliceInterval = window.setInterval(() => {
        if (recorder.state === "recording") recorder.requestData();
      }, 30000); // 30s chunks

      // Visual Ticker
      const startTs = Date.now();
      tickerRef.current = window.setInterval(() => {
        const elapsed = Math.floor((Date.now() - startTs) / 1000);
        setBufferSec(Math.min(300, elapsed));
      }, 1000);

      setIsLooping(true);
      // Store slice interval on a WeakMap to avoid polluting MediaRecorder type
      recorderSliceIntervals.set(recorder, sliceInterval);
    } catch (err) {
      setError("Hardware access denied. Camera/Mic required.");
    }
  };

  const stopLoop = useCallback(() => {
    if (recorderRef.current) {
      const interval = recorderRef.current ? recorderSliceIntervals.get(recorderRef.current) : undefined;
      if (interval) clearInterval(interval);
      recorderRef.current.stop();
    }
    if (tickerRef.current) clearInterval(tickerRef.current);
    if (streamRef.current) streamRef.current.getTracks().forEach((t) => t.stop());

    setIsLooping(false);
    setBufferSec(0);
  }, []);

  // 3. Save Final Buffer
  const finalizeBuffer = async () => {
    const db = await openDB();
    const tx = db.transaction(STORE_NAME, "readonly");
    const req = tx.objectStore(STORE_NAME).getAll();

    req.onsuccess = async () => {
      type LoopChunk = { id: string; blob: Blob; ts: number };
      const allChunks = (req.result as LoopChunk[]).sort((a, b) => a.ts - b.ts);
      if (allChunks.length === 0) return alert("Buffer empty.");

      const fullBlob = new Blob(
        allChunks.map((c) => c.blob),
        { type: "video/webm" },
      );

      // Compute Hash
      const hashBuffer = await crypto.subtle.digest("SHA-256", await fullBlob.arrayBuffer());
      const hash = Array.from(new Uint8Array(hashBuffer))
        .map((b) => b.toString(16).padStart(2, "0"))
        .join("");

      // Trigger Download / Save
      const url = URL.createObjectURL(fullBlob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `Witness_Loop_${new Date().getTime()}.webm`;
      a.click();

      alert(`Evidence preserved.\nHash: ${hash.substring(0, 12)}...`);
      stopLoop();
    };
  };

  useEffect(() => {
    return () => stopLoop(); // Cleanup on exit
  }, [stopLoop]);

  return (
    <div className="bg-black border border-red-900 rounded-3xl p-6 text-white max-w-sm mx-auto shadow-2xl">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-black italic text-red-600 uppercase tracking-tighter">
          Loop Guard
        </h2>
        <div
          className={`w-3 h-3 rounded-full ${isLooping ? "bg-red-500 animate-pulse shadow-[0_0_10px_#ff0000]" : "bg-gray-800"}`}
        />
      </div>

      {isLooping ? (
        <div className="space-y-6">
          <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800">
            <div className="flex justify-between text-[10px] font-bold text-gray-500 mb-2 uppercase">
              <span>Rolling Buffer</span>
              <span>
                {Math.floor(bufferSec / 60)}:{(bufferSec % 60).toString().padStart(2, "0")} / 5:00
              </span>
            </div>
            <div className="h-1.5 w-full bg-black rounded-full overflow-hidden">
              <div
                className="h-full bg-red-600 transition-all duration-1000 ease-linear"
                style={{ width: `${(bufferSec / 300) * 100}%` }}
              />
            </div>
          </div>

          <div className="grid grid-cols-1 gap-3">
            <button
              onClick={finalizeBuffer}
              className="w-full bg-red-600 py-4 rounded-xl font-black text-sm shadow-xl"
            >
              SAVE LAST 5 MINUTES
            </button>
            <button
              onClick={stopLoop}
              className="w-full bg-gray-900 border border-gray-700 py-3 rounded-xl font-bold text-xs text-gray-400"
            >
              STOP LOOP
            </button>
          </div>

          <div className="text-center">
            <button
              onClick={() => {
                alert("SOS DISPATCHED");
                finalizeBuffer();
              }}
              className="text-red-500 text-[10px] font-black underline uppercase tracking-widest animate-pulse"
            >
              ⚠️ I AM BEING DETAINED
            </button>
          </div>
        </div>
      ) : (
        <div className="py-6 text-center">
          <div className="text-4xl mb-4 opacity-20">🔄</div>
          <p className="text-xs text-gray-500 mb-6 px-4">
            Loop mode keeps a rolling 5-minute buffer of video in encrypted storage. Press start to
            begin monitoring.
          </p>
          <button
            onClick={startLoop}
            className="w-full bg-red-600 py-4 rounded-xl font-black text-lg tracking-widest"
          >
            START MONITOR
          </button>
          {error && <p className="mt-4 text-red-500 text-[10px] font-bold">{error}</p>}
        </div>
      )}

      <div className="mt-6 pt-6 border-t border-gray-900">
        <p className="text-[8px] text-gray-700 leading-tight uppercase font-medium text-center">
          Loop data is stored in the browser's temporary sandbox. <br />
          Files must be "Saved" to move them to the permanent vault.
        </p>
      </div>
    </div>
  );
}

// WitnessNightMode.tsx
import React, { useState, useEffect, useRef, useCallback } from "react";

// ------------------------------
// SECTION: TYPES
// ------------------------------
interface NightModeSettings {
  brightness: number;
  contrast: number;
  sharpen: boolean;
}

// ------------------------------
// SECTION: COMPONENT
// ------------------------------
export default function WitnessNightMode() {
  const [isActive, setIsActive] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [showSuggestion, setShowSuggestion] = useState(false);
  const [torchOn, setTorchOn] = useState(false);

  // Refs for high-performance processing (avoids React re-renders)
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number | undefined>(undefined);
  const lastFrameTime = useRef<number>(0);
  const streamRef = useRef<MediaStream | null>(null);
  const recorderRef = useRef<MediaRecorder | null>(null);

  const FRAME_INTERVAL = 1000 / 15; // Cap at 15 FPS for mobile stability

  // 1. Camera Initialization
  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: "environment", width: { ideal: 1280 } },
          audio: true,
        });
        streamRef.current = stream;
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.play();
        }
        requestRef.current = requestAnimationFrame(processLoop);
      } catch (err) {
        console.error("Camera access denied");
      }
    }
    startCamera();
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      streamRef.current?.getTracks().forEach((t) => t.stop());
    };
  }, [isActive]); // Re-init on mode toggle to ensure sync

  // 2. The Heavy Lifting: Pixel Processing Loop
  const processLoop = (time: number) => {
    if (time - lastFrameTime.current >= FRAME_INTERVAL) {
      lastFrameTime.current = time;
      renderFrame();
    }
    requestRef.current = requestAnimationFrame(processLoop);
  };

  const renderFrame = () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas || video.paused || video.ended) return;

    const ctx = canvas.getContext("2d", { alpha: false });
    if (!ctx) return;

    // Match dimensions
    if (canvas.width !== video.videoWidth) {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
    }

    ctx.drawImage(video, 0, 0);

    if (isActive) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const data = imageData.data;

      // Analysis: Check brightness every 100th pixel to save CPU
      let brightnessSum = 0;
      for (let i = 0; i < data.length; i += 400) {
        brightnessSum += (data[i] + data[i + 1] + data[i + 2]) / 3;
      }
      const avg = brightnessSum / (data.length / 400);
      if (avg < 40 && !showSuggestion) setShowSuggestion(true);

      // Processing: Single-pass adjustment (Brightness + Contrast)
      const b = 1.4; // Brightness multiplier
      const c = 1.2; // Contrast multiplier
      for (let i = 0; i < data.length; i += 4) {
        data[i] = (data[i] * b - 128) * c + 128; // R
        data[i + 1] = (data[i + 1] * b - 128) * c + 128; // G
        data[i + 2] = (data[i + 2] * b - 128) * c + 128; // B
      }
      ctx.putImageData(imageData, 0, 0);
    }
  };

  // 3. Torch Logic
  const toggleTorch = async () => {
    const track = streamRef.current?.getVideoTracks()[0];
    if (track && "torch" in track.getCapabilities()) {
      try {
        await track.applyConstraints({ advanced: [{ torch: !torchOn }] } as MediaTrackConstraints);
        setTorchOn(!torchOn);
      } catch (e) {
        console.warn("Torch not supported");
      }
    }
  };

  // 4. Recording Logic
  const startRecording = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const stream = canvas.captureStream(15);
    // Add audio back in
    const audioTrack = streamRef.current?.getAudioTracks()[0];
    if (audioTrack) stream.addTrack(audioTrack);

    const recorder = new MediaRecorder(stream, { mimeType: "video/webm" });
    recorderRef.current = recorder;
    recorder.start();
    setIsRecording(true);
  };

  const stopRecording = () => {
    recorderRef.current?.stop();
    setIsRecording(false);
    alert("Enhanced recording preserved in Vault.");
  };

  return (
    <div className="bg-black min-h-screen text-white p-4 font-sans">
      <header className="flex justify-between items-center mb-4">
        <h1 className="text-xl font-black italic text-red-600">NIGHT VISION</h1>
        <div className="flex gap-2">
          <button
            onClick={() => setIsActive(!isActive)}
            className={`px-4 py-1 rounded-full text-[10px] font-bold border transition-all ${isActive ? "bg-red-600 border-red-600" : "bg-gray-900 border-gray-700 text-gray-500"}`}
          >
            {isActive ? "ISO BOOST ACTIVE" : "STANDARD MODE"}
          </button>
        </div>
      </header>

      {/* Viewfinder */}
      <div className="relative aspect-video bg-zinc-900 rounded-3xl overflow-hidden border border-gray-800 shadow-2xl">
        <video ref={videoRef} className="hidden" muted playsInline />
        <canvas ref={canvasRef} className="w-full h-full object-cover" />

        {isActive && (
          <div className="absolute top-4 left-4 bg-red-600/20 text-red-500 px-2 py-1 rounded text-[9px] font-black border border-red-600/40 animate-pulse">
            DIGITAL GAIN ENABLED
          </div>
        )}

        {showSuggestion && !isActive && (
          <div className="absolute inset-x-4 bottom-4 bg-black/80 backdrop-blur-md border border-red-900 p-4 rounded-2xl animate-in slide-in-from-bottom-2">
            <p className="text-xs font-bold mb-2">Low light detected. Enable Night Vision?</p>
            <div className="flex gap-2">
              <button
                onClick={() => {
                  setIsActive(true);
                  setShowSuggestion(false);
                }}
                className="bg-red-600 text-[10px] font-black px-4 py-2 rounded-lg"
              >
                ENABLE
              </button>
              <button
                onClick={() => setShowSuggestion(false)}
                className="text-gray-500 text-[10px] px-2"
              >
                Dismiss
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="mt-8 flex flex-col items-center gap-6">
        <div className="flex gap-4">
          <button
            onClick={toggleTorch}
            className={`p-4 rounded-full border ${torchOn ? "bg-yellow-500/20 border-yellow-500 text-yellow-500" : "bg-gray-900 border-gray-800 text-gray-500"}`}
          >
            🔦
          </button>
          <button
            onClick={isRecording ? stopRecording : startRecording}
            className={`w-20 h-20 rounded-full border-4 flex items-center justify-center transition-all ${isRecording ? "border-gray-800 bg-red-600 animate-pulse" : "border-red-600 bg-transparent"}`}
          >
            <div
              className={`rounded-sm transition-all ${isRecording ? "w-6 h-6 bg-white" : "w-14 h-14 bg-red-600 rounded-full"}`}
            />
          </button>
          <button className="p-4 rounded-full bg-gray-900 border border-gray-800 text-gray-500">
            ⚙️
          </button>
        </div>

        <p className="text-[9px] text-gray-600 uppercase tracking-widest text-center">
          Digital gain increases noise. <br /> Use for visibility, not cinematic quality.
        </p>
      </div>
    </div>
  );
}

// WitnessRecordingContinuity.tsx
import React, { useState, useEffect, useCallback, useRef } from "react";

// ------------------------------
// SECTION: TYPES
// ------------------------------
export interface RecordingSegment {
  startTime: number;
  endTime: number;
}

export interface ContinuityLog {
  recordingId: string;
  segments: RecordingSegment[];
  totalRecordedMs: number;
  totalElapsedMs: number;
  hasGaps: boolean;
}

// ------------------------------
// SECTION: STORAGE (IndexedDB)
// ------------------------------
const DB_NAME = "WitnessContinuityDB";
const STORE_NAME = "continuity_logs";

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve) => {
    const request = indexedDB.open(DB_NAME, 2);
    request.onupgradeneeded = (e: IDBVersionChangeEvent) => {
      const db = (e.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: "recordingId" });
      }
    };
    request.onsuccess = () => resolve(request.result);
  });
};

// ------------------------------
// SECTION: UI COMPONENTS
// ------------------------------

export const ContinuityBadge: React.FC<{ hasGaps: boolean }> = ({ hasGaps }) => (
  <div style={hasGaps ? styles.badgeSegmented : styles.badgeContinuous}>
    <span style={!hasGaps ? styles.pulseDot : {}} />
    {hasGaps ? "SEGMENTED DATA" : "CONTINUOUS SOURCE"}
  </div>
);

export const ContinuityTimeline: React.FC<{ log: ContinuityLog }> = ({ log }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Handle High-DPI Scaling
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;

    // Draw Background
    ctx.fillStyle = "#111";
    ctx.fillRect(0, 0, width, height);

    const total = log.totalElapsedMs;

    log.segments.forEach((seg, i) => {
      const xStart = (seg.startTime / total) * width;
      const xEnd = (seg.endTime / total) * width;

      // Draw Segment (Green)
      ctx.fillStyle = "#4caf50";
      ctx.fillRect(xStart, 0, xEnd - xStart, height);

      // Label
      ctx.fillStyle = "rgba(255,255,255,0.7)";
      ctx.font = "bold 9px monospace";
      ctx.fillText(`S${i + 1}`, xStart + 2, 12);
    });

    // Draw Pauses (Hashed/Gray)
    for (let i = 0; i < log.segments.length - 1; i++) {
      const gapStart = (log.segments[i].endTime / total) * width;
      const gapEnd = (log.segments[i + 1].startTime / total) * width;
      ctx.fillStyle = "#333";
      ctx.fillRect(gapStart, 0, gapEnd - gapStart, height);
    }
  }, [log]);

  return (
    <div style={{ marginTop: 10 }}>
      <canvas ref={canvasRef} style={styles.timelineCanvas} />
      <div style={styles.timelineLegend}>
        <span style={{ color: "#4caf50" }}>■ RECORDING</span>
        <span style={{ color: "#444" }}>■ PAUSED</span>
      </div>
    </div>
  );
};

// ------------------------------
// SECTION: LOGIC & HOOK
// ------------------------------

export const generateContinuityCert = (log: ContinuityLog): string => {
  const status = log.hasGaps ? "SEGMENTED" : "CONTINUOUS";
  return `
AUDIT: RECORDING CONTINUITY REPORT
----------------------------------
ID: ${log.recordingId}
INTEGRITY STATUS: ${status}
TOTAL DURATION: ${(log.totalElapsedMs / 1000).toFixed(2)}s
ACTIVE FOOTAGE: ${(log.totalRecordedMs / 1000).toFixed(2)}s
SEGMENTS: ${log.segments.length}

${log.hasGaps ? "LEGAL NOTICE: Gaps detected in recording stream. Forensic timestamps provided for audit trail." : "VERIFIED: Uninterrupted single-stream capture."}
    `.trim();
};

export function useRecordingContinuity() {
  const [segments, setSegments] = useState<RecordingSegment[]>([]);
  const startTs = useRef<number>(0);

  const start = () => {
    startTs.current = Date.now();
    setSegments([{ startTime: 0, endTime: 0 }]);
  };

  const pause = () => {
    const elapsed = Date.now() - startTs.current;
    setSegments((prev) => {
      const last = [...prev];
      last[last.length - 1].endTime = elapsed;
      return last;
    });
  };

  const resume = () => {
    const elapsed = Date.now() - startTs.current;
    setSegments((prev) => [...prev, { startTime: elapsed, endTime: elapsed }]);
  };

  const stop = (id: string): ContinuityLog => {
    const elapsed = Date.now() - startTs.current;
    const finalSegments = [...segments];

    // Close the final open segment
    if (
      finalSegments[finalSegments.length - 1].endTime ===
      finalSegments[finalSegments.length - 1].startTime
    ) {
      finalSegments[finalSegments.length - 1].endTime = elapsed;
    }

    const recorded = finalSegments.reduce((s, seg) => s + (seg.endTime - seg.startTime), 0);

    const log: ContinuityLog = {
      recordingId: id,
      segments: finalSegments,
      totalRecordedMs: recorded,
      totalElapsedMs: elapsed,
      hasGaps: finalSegments.length > 1,
    };

    openDB().then((db) => {
      const tx = db.transaction(STORE_NAME, "readwrite");
      tx.objectStore(STORE_NAME).put(log);
    });

    return log;
  };

  return { start, pause, resume, stop };
}

