        <button
          key={size}
          type="button"
          onClick={() => updateScale(size)}
          className={`px-3 py-1 rounded-full text-xs border capitalize transition-all ${
            scale === size
              ? "bg-red-600 border-red-600 text-white"
              : "bg-black border-zinc-700 text-zinc-400 hover:border-red-600"
