// WitnessMultiDeviceSync.tsx
import React, { useState, useEffect, useRef, useMemo } from "react";

// ------------------------------
// SECTION: TYPES
// ------------------------------
export interface Device {
  id: string;
  name: string;
  lastSync: number;
  isPrimary: boolean;
}

export interface SyncConflict {
  id: string;
  localName: string;
  remoteName: string;
  localDate: number;
  remoteDate: number;
}

// ------------------------------
// SECTION: COMPONENT
// ------------------------------
export default function WitnessMultiDeviceSync({ userId }: { userId: string }) {
  const [devices, setDevices] = useState<Device[]>([]);
  const [syncStatus, setSyncStatus] = useState<"IDLE" | "SYNCING" | "ERROR">("IDLE");
  const [pairingFlow, setPairingFlow] = useState<"NONE" | "GENERATE" | "ENTER">("NONE");
  const [pairingCode, setPairingCode] = useState("");
  const [conflicts, setConflicts] = useState<SyncConflict[]>([]);

  const myDeviceId = useRef(localStorage.getItem("witness_device_id") || crypto.randomUUID());
  const syncTimer = useRef<number | null>(null);

  // 1. Initialization
  useEffect(() => {
    // Save my unique device ID if not exists
    localStorage.setItem("witness_device_id", myDeviceId.current);

    const savedDevices = localStorage.getItem("witness_synced_devices");
    if (savedDevices) {
      setDevices(JSON.parse(savedDevices));
    } else {
      // First time setup: auto-register this as primary
      const initial: Device = {
        id: myDeviceId.current,
        name: "Primary Mobile",
        lastSync: Date.now(),
        isPrimary: true,
      };
      setDevices([initial]);
      localStorage.setItem("witness_synced_devices", JSON.stringify([initial]));
    }

    // Start Simulation Heartbeat (checks for "Remote" updates)
    syncTimer.current = window.setInterval(performMockSync, 5000);

    return () => {
      if (syncTimer.current) clearInterval(syncTimer.current);
    };
  }, []);

  // 2. Sync Logic (Mocking Supabase/Realtime)
  const performMockSync = () => {
    setSyncStatus("SYNCING");

    // Check if a "remote" device added a pairing request in localStorage
    const pendingPair = localStorage.getItem("witness_pending_pair");
    if (pendingPair && pairingFlow === "GENERATE") {
      const data = JSON.parse(pendingPair);
      if (data.code === pairingCode) {
        addNewDevice(data.deviceName, data.deviceId);
        localStorage.removeItem("witness_pending_pair");
        setPairingFlow("NONE");
        alert("New Device Linked Successfully!");
      }
    }

    setTimeout(() => setSyncStatus("IDLE"), 1000);
  };

  // 3. Pairing Actions
  const startGeneratingCode = () => {
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    setPairingCode(code);
    setPairingFlow("GENERATE");
  };

  const handleJoinSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const code = formData.get("code") as string;
    const name = formData.get("name") as string;

    // Simulate sending code to "Primary" device via localStorage
    localStorage.setItem(
      "witness_pending_pair",
      JSON.stringify({
        code,
        deviceName: name,
        deviceId: myDeviceId.current,
      }),
    );

    alert("Request sent. Keep your primary device open to confirm.");
  };

  const addNewDevice = (name: string, id: string) => {
    const newDevice: Device = { id, name, lastSync: Date.now(), isPrimary: false };
    const updated = [...devices, newDevice];
    setDevices(updated);
    localStorage.setItem("witness_synced_devices", JSON.stringify(updated));
  };

  const removeDevice = (id: string) => {
    if (devices.find((d) => d.id === id)?.isPrimary) return alert("Cannot remove Primary device");
    const updated = devices.filter((d) => d.id !== id);
    setDevices(updated);
    localStorage.setItem("witness_synced_devices", JSON.stringify(updated));
  };

  return (
    <div className="min-h-screen bg-black text-white p-6 font-sans">
      <header className="mb-8">
        <h1 className="text-2xl font-black italic text-red-600">VAULT SYNC</h1>
        <div className="flex items-center gap-2 mt-1">
          <span
            className={`text-[10px] font-bold px-2 py-0.5 rounded ${syncStatus === "SYNCING" ? "bg-green-900 text-green-400 animate-pulse" : "bg-gray-900 text-gray-500"}`}
          >
            {syncStatus === "SYNCING" ? "REALTIME ACTIVE" : "ENCRYPTED & IDLE"}
          </span>
        </div>
      </header>

      {/* Device List */}
      <div className="bg-gray-900 rounded-2xl border border-gray-800 p-5 space-y-4 mb-6">
        <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest">
          Authorized Devices
        </h3>
        {devices.map((dev) => (
          <div
            key={dev.id}
            className="flex justify-between items-center bg-black/40 p-3 rounded-xl border border-gray-800"
          >
            <div>
              <div className="text-sm font-bold flex items-center gap-2">
                {dev.name}
                {dev.id === myDeviceId.current && (
                  <span className="text-[8px] bg-red-600 px-1 rounded uppercase">You</span>
                )}
              </div>
              <div className="text-[10px] text-gray-500">
                Last Sync: {new Date(dev.lastSync).toLocaleTimeString()}
              </div>
            </div>
            {!dev.isPrimary && (
              <button
                onClick={() => removeDevice(dev.id)}
                className="text-red-900 font-bold text-xs hover:text-red-500"
              >
                REVOKE
              </button>
            )}
          </div>
        ))}
      </div>

      {/* Pairing Logic UI */}
      {pairingFlow === "NONE" && (
        <div className="grid grid-cols-2 gap-4">
          <button
            onClick={startGeneratingCode}
            className="bg-red-600 py-4 rounded-xl font-bold text-xs"
          >
            ADD NEW DEVICE
          </button>
          <button
            onClick={() => setPairingFlow("ENTER")}
            className="bg-gray-800 border border-gray-700 py-4 rounded-xl font-bold text-xs"
          >
            JOIN SYNC CHAIN
          </button>
        </div>
      )}

      {pairingFlow === "GENERATE" && (
        <div className="bg-red-950/20 border-2 border-red-600 rounded-2xl p-8 text-center animate-in fade-in zoom-in">
          <p className="text-xs text-red-500 font-bold uppercase mb-2">
            Primary Authorization Code
          </p>
          <div className="text-5xl font-black tracking-tighter mb-4">{pairingCode}</div>
          <p className="text-[10px] text-gray-400 leading-tight">
            Enter this code on your second device.
            <br />
            Valid for 5 minutes.
          </p>
          <button
            onClick={() => setPairingFlow("NONE")}
            className="mt-6 text-xs text-gray-500 underline"
          >
            Cancel Pairing
          </button>
        </div>
      )}

      {pairingFlow === "ENTER" && (
        <form
          onSubmit={handleJoinSubmit}
          className="bg-gray-900 border border-gray-800 rounded-2xl p-6 space-y-4"
        >
          <div>
            <label className="text-[10px] font-bold text-gray-500 uppercase">Device Name</label>
            <input
              name="name"
              required
              placeholder="e.g. iPad Pro"
              className="w-full bg-black border border-gray-700 p-3 rounded-lg mt-1"
            />
          </div>
          <div>
            <label className="text-[10px] font-bold text-gray-500 uppercase">Pairing Code</label>
            <input
              name="code"
              required
              maxLength={6}
              placeholder="000000"
              className="w-full bg-black border border-gray-700 p-3 rounded-lg mt-1 text-center text-2xl font-black"
            />
          </div>
          <button type="submit" className="w-full bg-red-600 py-4 rounded-xl font-bold">
            REQUEST ACCESS
          </button>
          <button
            type="button"
            onClick={() => setPairingFlow("NONE")}
            className="w-full text-xs text-gray-500"
          >
            Cancel
          </button>
        </form>
      )}

      {/* Conflict Resolution Section */}
      {conflicts.length > 0 && (
        <div className="mt-10 space-y-4">
          <h3 className="text-red-500 font-bold text-sm uppercase">Sync Conflicts Detected</h3>
          {conflicts.map((c) => (
            <div key={c.id} className="bg-gray-900 p-4 rounded-xl border border-red-900">
              <p className="text-xs font-bold mb-3">Recording: {c.localName}</p>
              <div className="grid grid-cols-2 gap-2">
                <button className="bg-gray-800 p-2 rounded text-[10px]">
                  Keep Local ({new Date(c.localDate).toLocaleDateString()})
                </button>
                <button className="bg-red-900 p-2 rounded text-[10px]">
                  Use Remote ({new Date(c.remoteDate).toLocaleDateString()})
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <div className="mt-12 text-center">
        <p className="text-[9px] text-gray-600 uppercase tracking-widest leading-loose">
          E2E Encrypted • PBKDF2 Key Derivation • No Cleartext Storage
        </p>
      </div>
    </div>
  );
}

