// ------------------------------
// SECTION: Types & Global State Definitions
// ------------------------------
type AuthStatus = "unauthenticated" | "authenticated";
type VaultLockStatus = "locked" | "unlocked";
type RecordingStatus = "idle" | "recording" | "paused";
type LiveStatus = "off" | "connecting" | "live";
type SOSStatus = "inactive" | "active" | "escalating";

interface UserLocation {
  lat: number;
  lng: number;
  accuracy?: number;
}

interface AppState {
  authStatus: AuthStatus;
  vaultLockStatus: VaultLockStatus;
  recordingStatus: RecordingStatus;
  liveStatus: LiveStatus;
  sosStatus: SOSStatus;
  activeUserLocation: UserLocation | null;
  onboardingCompleted: boolean;
  pinLockoutUntil: number | null;
  stealthMode: boolean;
  isEmergencyActive: boolean;
  pendingUploads: number;
  syncStatus: "online" | "offline" | "syncing";
  decoyMode: boolean;
}

type AppAction =
  | { type: "SET_AUTH"; payload: AuthStatus }
  | { type: "SET_VAULT_LOCK"; payload: VaultLockStatus }
  | { type: "SET_RECORDING"; payload: RecordingStatus }
  | { type: "SET_LIVE"; payload: LiveStatus }
  | { type: "SET_SOS"; payload: SOSStatus }
  | { type: "SET_LOCATION"; payload: UserLocation | null }
  | { type: "SET_ONBOARDING"; payload: boolean }
  | { type: "SET_PIN_LOCKOUT"; payload: number | null }
  | { type: "TOGGLE_STEALTH_MODE" }
  | { type: "SET_EMERGENCY"; payload: boolean }
  | { type: "SET_PENDING_UPLOADS"; payload: number }
  | { type: "SET_SYNC_STATUS"; payload: "online" | "offline" | "syncing" }
  | { type: "SET_DECOY_MODE"; payload: boolean };

const initialState: AppState = {
  authStatus: "unauthenticated",
  vaultLockStatus: "locked",
  recordingStatus: "idle",
  liveStatus: "off",
  sosStatus: "inactive",
  activeUserLocation: null,
  onboardingCompleted: false,
  pinLockoutUntil: null,
  stealthMode: false,
  isEmergencyActive: false,
  pendingUploads: 0,
  syncStatus: "online",
  decoyMode: false,
};

function appReducer(state: AppState, action: AppAction): AppState {
  switch (action.type) {
    case "SET_AUTH":
      return { ...state, authStatus: action.payload };
    case "SET_VAULT_LOCK":
      return { ...state, vaultLockStatus: action.payload };
    case "SET_RECORDING":
      return { ...state, recordingStatus: action.payload };
    case "SET_LIVE":
      return { ...state, liveStatus: action.payload };
    case "SET_SOS":
      return { ...state, sosStatus: action.payload };
    case "SET_LOCATION":
      return { ...state, activeUserLocation: action.payload };
    case "SET_ONBOARDING":
      return { ...state, onboardingCompleted: action.payload };
    case "SET_PIN_LOCKOUT":
      return { ...state, pinLockoutUntil: action.payload };
    case "TOGGLE_STEALTH_MODE":
      return { ...state, stealthMode: !state.stealthMode };
    case "SET_EMERGENCY":
      return { ...state, isEmergencyActive: action.payload };
    case "SET_PENDING_UPLOADS":
      return { ...state, pendingUploads: action.payload };
    case "SET_SYNC_STATUS":
      return { ...state, syncStatus: action.payload };
    case "SET_DECOY_MODE":
      return { ...state, decoyMode: action.payload };
    default:
      return state;
  }
}

// ------------------------------
// SECTION: Global State Orchestrator (WitnessProvider)
// ------------------------------
interface WitnessContextValue extends AppState {
  dispatch: React.Dispatch<AppAction>;
  startRecording: () => void;
  stopRecording: () => void;
  startLive: () => void;
  stopLive: () => void;
  triggerSOS: () => void;
  emergencyOverride: () => void;
  resolveEmergency: () => void;
  unlockVault: (pin: string) => boolean;
  lockVault: () => void;
}

const WitnessContext = createContext<WitnessContextValue | undefined>(undefined);

export function useWitness() {
  const ctx = useContext(WitnessContext);
  if (!ctx) throw new Error("useWitness must be used within WitnessProvider");
  return ctx;
}

export function WitnessProvider({ children }: { children: React.ReactNode }) {
  const [state, dispatch] = useReducer(appReducer, initialState);
  const [pinAttempts, setPinAttempts] = useState(0);
  const { shortPulse, doublePulse, longPulse } = useWitnessHaptics();

  const startRecording = useCallback(() => {
    if (state.isEmergencyActive || state.liveStatus === "live") return;
    dispatch({ type: "SET_RECORDING", payload: "recording" });
    shortPulse();
  }, [state.isEmergencyActive, state.liveStatus, shortPulse]);

  const stopRecording = useCallback(() => {
    dispatch({ type: "SET_RECORDING", payload: "idle" });
    shortPulse();
  }, [shortPulse]);

  const startLive = useCallback(() => {
    if (state.isEmergencyActive) return;
    dispatch({ type: "SET_LIVE", payload: "live" });
  }, [state.isEmergencyActive]);

  const stopLive = useCallback(() => {
    dispatch({ type: "SET_LIVE", payload: "off" });
  }, []);

  const triggerSOS = useCallback(() => {
    dispatch({ type: "SET_SOS", payload: "active" });
    dispatch({ type: "SET_EMERGENCY", payload: true });
    doublePulse();
    console.log("[SOS] Emergency triggered");
  }, [doublePulse]);

  const emergencyOverride = useCallback(() => {
    dispatch({ type: "SET_EMERGENCY", payload: true });
    dispatch({ type: "SET_SOS", payload: "active" });
    dispatch({ type: "SET_LIVE", payload: "live" });
    if (!state.stealthMode) dispatch({ type: "TOGGLE_STEALTH_MODE" });
    doublePulse();
  }, [state.stealthMode, doublePulse]);

  const resolveEmergency = useCallback(() => {
    dispatch({ type: "SET_EMERGENCY", payload: false });
    dispatch({ type: "SET_SOS", payload: "inactive" });
    shortPulse();
  }, [shortPulse]);

  const unlockVault = useCallback(
    (pin: string) => {
      if (pin === "1234") {
        dispatch({ type: "SET_VAULT_LOCK", payload: "unlocked" });
        dispatch({ type: "SET_DECOY_MODE", payload: false });
        setPinAttempts(0);
        shortPulse();
        return true;
      } else if (pin === "9999") {
        dispatch({ type: "SET_VAULT_LOCK", payload: "unlocked" });
        dispatch({ type: "SET_DECOY_MODE", payload: true });
        setPinAttempts(0);
        shortPulse();
        return true;
      } else {
        const newAttempts = pinAttempts + 1;
        setPinAttempts(newAttempts);
        longPulse();
        if (newAttempts >= 5) {
          dispatch({ type: "SET_PIN_LOCKOUT", payload: Date.now() + 30 * 1000 });
          setTimeout(() => dispatch({ type: "SET_PIN_LOCKOUT", payload: null }), 30000);
        }
        return false;
      }
    },
    [pinAttempts, shortPulse, longPulse],
  );

  const lockVault = useCallback(() => {
    dispatch({ type: "SET_VAULT_LOCK", payload: "locked" });
  }, []);

  const value: WitnessContextValue = {
    ...state,
    dispatch,
    startRecording,
    stopRecording,
    startLive,
    stopLive,
    triggerSOS,
    emergencyOverride,
    resolveEmergency,
    unlockVault,
    lockVault,
  };

  return <WitnessContext.Provider value={value}>{children}</WitnessContext.Provider>;
}

// ------------------------------
// SECTION: Emergency Priority Handling (useEmergencyIntervention)
// ------------------------------
export function useEmergencyIntervention() {
  const { isEmergencyActive, emergencyOverride, resolveEmergency } = useWitness();
  useEffect(() => {
    if (isEmergencyActive) {
      document.body.style.overflow = "hidden";
      return () => {
        document.body.style.overflow = "";
      };
    }
  }, [isEmergencyActive]);
  return { isEmergencyActive, emergencyOverride, resolveEmergency };
}

// ------------------------------
// SECTION: Supabase Realtime & Geo-Sync (useGlobalSync)
// ------------------------------
export function useGlobalSync() {
  const { activeUserLocation, syncStatus } = useWitness();
  const [nearbySOS, setNearbySOS] = useState<
    { id: number; lat: number; lng: number; timestamp: string }[]
  >([]);

  useEffect(() => {
    const interval = setInterval(() => {
      if (Math.random() < 0.1) {
        const mockSOS = {
          id: Date.now(),
          lat: activeUserLocation?.lat || 0,
          lng: activeUserLocation?.lng || 0,
          timestamp: new Date().toISOString(),
        };
        setNearbySOS((prev) => [mockSOS, ...prev].slice(0, 10));
        console.log("[Realtime] Nearby SOS detected");
      }
    }, 30000);
    return () => clearInterval(interval);
  }, [activeUserLocation]);

  useEffect(() => {
    const killCheck = setInterval(() => {
      const killFlag = localStorage.getItem("witness_kill_switch");
      if (killFlag === "true") {
        localStorage.clear();
        indexedDB.deleteDatabase("WitnessDB");
        alert("Device wiped by remote command.");
      }
    }, 10000);
    return () => clearInterval(killCheck);
  }, []);

  return { nearbySOS, syncStatus };
}

// ------------------------------
// SECTION: Unified Encryption Bridge (useCryptoBridge)
// ------------------------------
export function useCryptoBridge() {
  const { vaultLockStatus, decoyMode } = useWitness();
  const [masterKey, setMasterKey] = useState<CryptoKey | null>(null);
  const [derivedKey, setDerivedKey] = useState<string | null>(null);

  const unlock = useCallback(async (pin: string) => {
    const mockKey = await crypto.subtle.generateKey({ name: "AES-GCM", length: 256 }, true, [
      "encrypt",
      "decrypt",
    ]);
    setMasterKey(mockKey);
    setDerivedKey(window.btoa(pin));
    return true;
  }, []);

  const lock = useCallback(() => {
    setMasterKey(null);
    setDerivedKey(null);
  }, []);

  const encryptBuffer = useCallback(
    async (data: ArrayBuffer) => {
      if (!masterKey) throw new Error("Vault locked");
      const iv = crypto.getRandomValues(new Uint8Array(12));
      const ciphertext = await crypto.subtle.encrypt(
        { name: "AES-GCM", iv: iv as any },
        masterKey,
        data,
      );
      return { ciphertext, iv };
    },
    [masterKey],
  );

  const decryptBuffer = useCallback(
    async (ciphertext: ArrayBuffer, iv: Uint8Array) => {
      if (!masterKey) throw new Error("Vault locked");
      return await crypto.subtle.decrypt({ name: "AES-GCM", iv: iv as any }, masterKey, ciphertext);
    },
    [masterKey],
  );

  useEffect(() => {
    if (vaultLockStatus === "locked") lock();
  }, [vaultLockStatus, lock]);

  return {
    masterKey: derivedKey,
    isUnlocked: vaultLockStatus === "unlocked" && masterKey !== null,
    decryptMode: decoyMode,
    encryptBuffer,
    decryptBuffer,
    unlock,
    lock,
  };
}

// ------------------------------
// SECTION: Global Haptic & Audio Feedback Controller (FeedbackNexus)
// ------------------------------
export function useWitnessHaptics() {
  const shortPulse = useCallback(
    () => window.navigator.vibrate && window.navigator.vibrate(50),
    [],
  );
  const doublePulse = useCallback(
    () => window.navigator.vibrate && window.navigator.vibrate([50, 50, 100]),
    [],
  );
  const longPulse = useCallback(
    () => window.navigator.vibrate && window.navigator.vibrate(200),
    [],
  );
  const errorPulse = useCallback(
    () => window.navigator.vibrate && window.navigator.vibrate([100, 50, 100, 50, 200]),
    [],
  );
  return { shortPulse, doublePulse, longPulse, errorPulse };
}

export function useAudioFeedback() {
  const [enabled, setEnabled] = useState(true);
  const playBeep = useCallback(() => {
    if (!enabled) return;
    const AudioCtx = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioCtx) return;
    const audioContext = new AudioCtx();
    const oscillator = audioContext.createOscillator();
    const gain = audioContext.createGain();
    oscillator.connect(gain);
    gain.connect(audioContext.destination);
    oscillator.frequency.value = 880;
    gain.gain.value = 0.1;
    oscillator.start();
    gain.gain.exponentialRampToValueAtTime(0.00001, audioContext.currentTime + 0.5);
    oscillator.stop(audioContext.currentTime + 0.5);
  }, [enabled]);
  return { playBeep, enabled, setEnabled };
}

export function FeedbackNexus() {
  const { recordingStatus, liveStatus, sosStatus } = useWitness();
  const { shortPulse, doublePulse } = useWitnessHaptics();
  const { playBeep } = useAudioFeedback();

  useEffect(() => {
    if (recordingStatus === "recording") playBeep();
  }, [recordingStatus, playBeep]);

  useEffect(() => {
    if (liveStatus === "live") shortPulse();
  }, [liveStatus, shortPulse]);

  useEffect(() => {
    if (sosStatus === "active") doublePulse();
  }, [sosStatus, doublePulse]);

  return null;
}

// ------------------------------
// SECTION: Storage & Cache Reconciler (StorageNexus)
// ------------------------------
export function useStorageNexus() {
  const { dispatch, pendingUploads } = useWitness();
  const [queue, setQueue] = useState<{ id: number; blob: Blob; metadata: any }[]>([]);

  const processQueue = useCallback(async () => {
    if (queue.length === 0) return;
    dispatch({ type: "SET_SYNC_STATUS", payload: "syncing" });
    for (const item of queue) {
      console.log(`Uploading recording ${item.id}`);
      await new Promise((r) => setTimeout(r, 1000));
      setQueue((prev) => prev.filter((i) => i.id !== item.id));
      dispatch({ type: "SET_PENDING_UPLOADS", payload: Math.max(0, pendingUploads - 1) });
    }
    dispatch({ type: "SET_SYNC_STATUS", payload: "online" });
  }, [queue, dispatch, pendingUploads]);

  const addToQueue = useCallback(
    async (recordingBlob: Blob, metadata: any) => {
      const item = { id: Date.now(), blob: recordingBlob, metadata };
      setQueue((prev) => [...prev, item]);
      dispatch({ type: "SET_PENDING_UPLOADS", payload: pendingUploads + 1 });
      setTimeout(() => processQueue(), 500);
    },
    [pendingUploads, dispatch, processQueue],
  );

  useEffect(() => {
    const handleOnline = () => {
      dispatch({ type: "SET_SYNC_STATUS", payload: "online" });
      processQueue();
    };
    window.addEventListener("online", handleOnline);
    return () => window.removeEventListener("online", handleOnline);
  }, [processQueue, dispatch]);

  return { addToQueue, pendingUploads, queue };
}

