// ------------------------------
// SECTION: Haptics Helper
// ------------------------------
function useHaptics() {
  const shortPulse = () => {
    if (typeof navigator !== "undefined" && navigator.vibrate) {
      navigator.vibrate(50);
    }
  };
  return { shortPulse };
}

// ------------------------------
// SECTION: Signup Flow with Phone OTP (WitnessSignup)
// ------------------------------
export function WitnessSignup({ onSuccess }: { onSuccess: () => void }) {
  const [step, setStep] = useState<"phone" | "otp">("phone");
  const [phone, setPhone] = useState("");
  const [otp, setOtp] = useState("");
  const [error, setError] = useState("");
  const { shortPulse } = useHaptics();

  const sendOtp = async () => {
    if (!phone.match(/^\+?[1-9]\d{9,14}$/)) {
      setError("Enter valid phone number with country code");
      return;
    }
    const { error: err } = await supabaseMock.auth.signInWithOtp({ phone });
    if (err) {
      setError("Failed to send code");
    } else {
      setStep("otp");
      shortPulse();
    }
  };

  const verifyOtp = async () => {
    if (otp !== "123456") {
      setError("Invalid OTP");
      return;
    }
    const { error: err } = await supabaseMock.auth.signUp({ phone });
    if (err) {
      setError((err as any).message);
    } else {
      shortPulse();
      onSuccess();
    }
  };

  return (
    <div className="bg-black p-6 rounded-xl border-l-4 border-red-600 max-w-md w-full shadow-2xl">
      <h2 className="text-2xl font-black text-red-600 mb-6 uppercase italic tracking-tighter">
        Initialize Identity
      </h2>
      {step === "phone" && (
        <div className="space-y-4">
          <input
            type="tel"
            placeholder="+1 234 567 8900"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-800 focus:border-red-600 rounded-lg px-4 py-3 text-white outline-none transition-colors"
          />
          {error && <p className="text-red-500 text-xs font-bold uppercase italic">{error}</p>}
          <button
            onClick={sendOtp}
            className="bg-red-600 hover:bg-red-700 text-white font-black py-3 rounded-full w-full uppercase tracking-widest transition-all"
          >
            Send Secure OTP
          </button>
        </div>
      )}
      {step === "otp" && (
        <div className="space-y-4">
          <input
            type="text"
            placeholder="Verification Code"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            className="w-full bg-zinc-900 border border-zinc-800 focus:border-red-600 rounded-lg px-4 py-3 text-white text-center tracking-[0.5em] text-xl font-mono outline-none transition-colors"
          />
          {error && <p className="text-red-500 text-xs font-bold uppercase italic">{error}</p>}
          <button
            onClick={verifyOtp}
            className="bg-red-600 hover:bg-red-700 text-white font-black py-3 rounded-full w-full uppercase tracking-widest transition-all"
          >
            Verify Protocol
          </button>
          <button
            onClick={() => setStep("phone")}
            className="text-zinc-500 text-xs font-bold uppercase hover:text-white w-full"
          >
            Change Phone
          </button>
        </div>
      )}
    </div>
  );
}

