}

// ------------------------------
// SECTION: Identity Re-verification OTP (IdentityVerify)
// ------------------------------
export function useIdentityVerify() {
  const [step, setStep] = useState<"idle" | "verify">("idle");
  const [otp, setOtp] = useState("");
  const { shortPulse } = useHaptics();

  const sendVerification = async (phone: string) => {
    const { error: err } = await supabaseMock.auth.signInWithOtp({ phone });
    if (!err) {
      setStep("verify");
      shortPulse();
    }
  };

  const verifyCode = async (code: string) => {
    if (code === "123456") {
      setStep("idle");
      shortPulse();
      return true;
    }
    return false;
  };

  return { sendVerification, verifyCode, step, otp, setOtp };
}

// ------------------------------
// SECTION: Vault Re-encryption (ChangePinReencrypt)
// ------------------------------
export function useChangePinReencrypt() {
  const [currentPin, setCurrentPin] = useState("");
  const [newPin, setNewPin] = useState("");
  const [confirmPin, setConfirmPin] = useState("");
  const [error, setError] = useState("");
  const { shortPulse } = useHaptics();

  const handleSubmit = async () => {
    if (newPin !== confirmPin) {
      setError("PIN confirmation mismatch");
      return;
    }
    if (!/^\d{4}$/.test(newPin)) {
      setError("PIN must be 4 digits");
      return;
    }
    // Simulate re-encryption
    localStorage.setItem("witness_encrypted_master", `bin_${newPin}_locked`);
    alert("Vault re-encrypted with new master key.");
    shortPulse();
    setCurrentPin("");
    setNewPin("");
    setConfirmPin("");
    setError("");
  };

  return {
    currentPin,
    setCurrentPin,
    newPin,
    setNewPin,
    confirmPin,
    setConfirmPin,
    error,
    handleSubmit,
  };
}

// ------------------------------
// SECTION: Biometric Unlock (BiometricAuth)
// ------------------------------
export function BiometricAuth({ onAuthenticated }: { onAuthenticated: () => void }) {
  const [available, setAvailable] = useState<boolean | null>(null);
  const { shortPulse } = useHaptics();

  useEffect(() => {
    if (
      (window as any).PublicKeyCredential &&
      typeof (window as any).PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable ===
        "function"
    ) {
      (window as any).PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable().then(
        (res: boolean) => setAvailable(res),
      );
    } else {
      setAvailable(false);
    }
  }, []);

  const handleBiometric = async () => {
    if (!available) return;
    const success = Math.random() > 0.1; // Simulated
    if (success) {
      shortPulse();
      onAuthenticated();
    } else {
      alert("Biometric verification failed.");
    }
  };

  return (
    <div className="bg-zinc-950 p-5 rounded-2xl border border-zinc-900 flex justify-between items-center shadow-lg">
      <div className="flex flex-col">
        <span className="text-white font-bold text-sm">Biometric Access</span>
        <span className="text-zinc-600 text-[10px] uppercase font-black tracking-widest">
          Face ID / Fingerprint
        </span>
      </div>
      <button
        onClick={handleBiometric}
        className="bg-red-600 hover:bg-red-700 text-white font-black px-5 py-2 rounded-full text-[10px] uppercase tracking-tighter transition-all disabled:opacity-30"
        disabled={available === false}
      >
        {available === null ? "Detecting..." : available ? "Authenticate" : "Unsupported"}
      </button>
    </div>
  );
}

// ------------------------------
// SECTION: Session Persistence (usePersistentSession)
// ------------------------------
export function usePersistentSession() {
  const [isVaultLocked, setIsVaultLocked] = useState(true);

  useEffect(() => {
    const stored = localStorage.getItem("witness_vault_locked");
    if (stored !== null) setIsVaultLocked(stored === "true");
  }, []);

  const unlockVault = () => {
    setIsVaultLocked(false);
    localStorage.setItem("witness_vault_locked", "false");
  };

  const lockVault = () => {
    setIsVaultLocked(true);
    localStorage.setItem("witness_vault_locked", "true");
  };

  return { isVaultLocked, unlockVault, lockVault };
}

