export function SecurePinEditor(): JSX.Element {
  const [step, setStep] = useState<"current" | "new" | "confirm">("current");

  const [currentPin, setCurrentPin] = useState("");

  const [newPin, setNewPin] = useState("");

  const [confirmPin, setConfirmPin] = useState("");

  const [error, setError] = useState("");

  const [showForgot, setShowForgot] = useState(false);

  const [forgotPhone, setForgotPhone] = useState("");

  const [otpCode, setOtpCode] = useState("");

  const [otpSent, setOtpSent] = useState(false);

  const { shortPulse } = useHaptics();

  const verifyCurrent = (): void => {
    if (currentPin !== "1234") {
      setError("Incorrect current PIN");

      return;
    }

    setError("");
    setStep("new");
  };

  const saveNewPin = (): void => {
    if (!/^\d{4}$/.test(newPin)) {
      setError("PIN must be 4 digits");

      return;
    }

    if (newPin !== confirmPin) {
      setError("PINs do not match");

      return;
    }

    shortPulse();

    if (isBrowser()) {
      alert("PIN changed successfully. Vault re-encrypted.");
    }

    setStep("current");

    setCurrentPin("");

    setNewPin("");

    setConfirmPin("");

    setError("");
  };

  const sendForgotOtp = async (): Promise<void> => {
    if (!forgotPhone) {
      return;
    }

    await sendOTP(forgotPhone);

    setOtpSent(true);
  };

  const verifyForgot = async (): Promise<void> => {
    const valid = await verifyOTP(forgotPhone, otpCode);

    if (valid) {
      if (isBrowser()) {
        alert("Identity verified. You can now set a new PIN.");
      }

      setShowForgot(false);

      setStep("new");
    } else {
      setError("Invalid OTP");
    }
  };

  if (showForgot) {
    return (
      <div className="bg-black border border-red-600 p-3 rounded-lg">
        <h4 className="font-bold text-red-500 mb-2">Forgot PIN</h4>

        <input
          type="tel"
          placeholder="Phone number"
          value={forgotPhone}
          onChange={(event) => setForgotPhone(event.target.value)}
          className="w-full bg-black border border-red-600 rounded px-2 py-1 text-sm text-white mb-2"
        />

        {!otpSent ? (
          <button
            type="button"
            onClick={sendForgotOtp}
