// SECTION: WebAuthn Biometrics (BiometricEnroller)
// ------------------------------
export function BiometricEnroller(): JSX.Element {
  const [credentials, setCredentials] = useState<BiometricCredential[]>(() => {
    const stored = safeStorage.get("biometric_creds");

    return stored ? JSON.parse(stored) : [];
  });

  const [supported, setSupported] = useState(true);

  useEffect(() => {
    if (!isBrowser() || !("PublicKeyCredential" in window)) {
      setSupported(false);
    }
  }, []);

  const enroll = async (): Promise<void> => {
    if (!supported) {
      if (isBrowser()) {
        alert("WebAuthn not supported on this device.");
      }

      return;
    }

    const newCredential: BiometricCredential = {
      id: genId(),
      name: `Biometric ${credentials.length + 1}`,
      createdAt: Date.now(),
      lastUsed: Date.now(),
    };

    const updated = [...credentials, newCredential];

    setCredentials(updated);

    safeStorage.set("biometric_creds", JSON.stringify(updated));

    if (isBrowser()) {
      alert("Biometric enrolled successfully.");
    }
  };

  const removeCredential = (id: string): void => {
    const updated = credentials.filter((credential) => credential.id !== id);

    setCredentials(updated);

    safeStorage.set("biometric_creds", JSON.stringify(updated));
  };

  return (
    <div className="space-y-3">
      <div className="flex justify-between items-center">
        <h4 className="font-bold text-red-500">Biometric Unlock</h4>

        {!supported && <span className="text-xs text-white">Not supported</span>}
      </div>

      {credentials.map((credential) => (
        <div
          key={credential.id}
          className="bg-black border border-red-600 p-2 rounded-lg flex justify-between items-center"
        >
          <div>
            <div className="text-sm text-white">Device: {credential.name}</div>

            <div className="text-xs text-white">
              Last used: {new Date(credential.lastUsed).toLocaleString()}
            </div>
          </div>

          <button
            type="button"
            onClick={() => removeCredential(credential.id)}
            className="text-red-500 text-xs"
          >
            Remove
          </button>
        </div>
      ))}

      <button
        type="button"
        onClick={enroll}
        disabled={!supported}
        className="bg-red-600 px-4 py-2 rounded-full text-sm w-full text-white disabled:opacity-50"
      >
        Enroll Biometric
      </button>
    </div>
  );
}

// ------------------------------
// SECTION: Account Deletion (NuclearDelete)
// ------------------------------
export function NuclearDelete(): JSX.Element {
  const [step, setStep] = useState<"confirm" | "otp">("confirm");

  const [phone, setPhone] = useState("");

  const [otp, setOtp] = useState("");

  const [error, setError] = useState("");

  const { longPulse } = useHaptics();

  const sendOtp = async (): Promise<void> => {
    if (!phone) {
      return;
    }

    await sendOTP(phone);

    setStep("otp");
  };

  const confirmDelete = async (): Promise<void> => {
    const valid = await verifyOTP(phone, otp);

    if (!valid) {
      setError("Invalid OTP");

      return;
    }

    longPulse();

    safeStorage.clear();

    if (isBrowser()) {
      sessionStorage.clear();

      indexedDB.deleteDatabase("WitnessDB");

      alert("Account and all data permanently deleted.");

      window.location.href = "/";
    }
  };

  return (
    <div className="bg-black border border-red-600 rounded-lg p-3 space-y-3">
      <h4 className="font-bold text-red-500">⚠ Delete Account</h4>

      <p className="text-sm text-white">This action is permanent.</p>

      {step === "confirm" && (
        <>
          <input
            type="tel"
            placeholder="Phone number"
            value={phone}
            onChange={(event) => setPhone(event.target.value)}
            className="w-full bg-black border border-red-600 rounded px-3 py-2 text-white"
          />

          <button
            type="button"
            onClick={sendOtp}
            className="bg-red-600 px-4 py-2 rounded-full text-sm w-full text-white"
          >
            Send OTP
          </button>
        </>
      )}

      {step === "otp" && (
        <>
          <input
            type="text"
            placeholder="6-digit code"
            value={otp}
            onChange={(event) => setOtp(event.target.value)}
            className="w-full bg-black border border-red-600 rounded px-3 py-2 text-white"
          />

          {error && <p className="text-red-500 text-sm">{error}</p>}

          <button
            type="button"
            onClick={confirmDelete}
            className="bg-red-600 px-4 py-2 rounded-full text-sm w-full text-white"
          >
            Permanently Delete
          </button>
        </>
      )}
    </div>
  );
}

