export function usePreferences() {
  const [prefs, setPrefs] = useState<UserPreferences>(() => {
    const stored = safeStorage.get("user_preferences");

    return stored
      ? JSON.parse(stored)
      : {
          theme: "dark",
          notifications: {
            sosAlerts: true,
            nearbyIncidents: true,
            liveStreams: true,
          },
        };
  });

  const updateTheme = (theme: "dark" | "light"): void => {
    const updated = {
      ...prefs,
      theme,
    };

    setPrefs(updated);

    safeStorage.set("user_preferences", JSON.stringify(updated));

    if (isBrowser()) {
      document.documentElement.classList.remove("light-theme");
    }
  };

  const updateNotification = async (
    key: keyof UserPreferences["notifications"],
    value: boolean,
  ): Promise<void> => {
    const updated = {
      ...prefs,
      notifications: {
        ...prefs.notifications,
        [key]: value,
      },
    };

    setPrefs(updated);

    safeStorage.set("user_preferences", JSON.stringify(updated));

    await supabaseMock.from("push_subscriptions").upsert({
      user_id: "current",
      preferences: updated.notifications,
    });
  };

  return {
    prefs,
    updateTheme,
    updateNotification,
  };
}

