export function TrustedContactSetup(): JSX.Element {
  const [contacts, setContacts] = useState<TrustedContact[]>(() => {
    const stored = safeStorage.get("trusted_contacts");

    return stored ? JSON.parse(stored) : [];
  });

  const [name, setName] = useState("");

  const [phone, setPhone] = useState("");

  const [verifyingId, setVerifyingId] = useState<string | null>(null);

  const [otp, setOtp] = useState("");

  const { shortPulse } = useHaptics();

  const addContact = async (): Promise<void> => {
    if (!name || !phone) {
      return;
    }

    const newContact: TrustedContact = {
      id: genId(),
      name,
      phone,
      verified: false,
    };

    const updated = [...contacts, newContact];

    setContacts(updated);

    safeStorage.set("trusted_contacts", JSON.stringify(updated));

    setName("");
    setPhone("");

    await sendOTP(phone);

    setVerifyingId(newContact.id);
  };

  const verifyContact = async (id: string): Promise<void> => {
    const contact = contacts.find((current) => current.id === id);

    if (!contact) {
      return;
    }

    const valid = await verifyOTP(contact.phone, otp);

    if (valid) {
      const updated = contacts.map((current) =>
        current.id === id
          ? {
              ...current,
              verified: true,
            }
          : current,
      );

      setContacts(updated);

      safeStorage.set("trusted_contacts", JSON.stringify(updated));

      setVerifyingId(null);

      setOtp("");

      shortPulse();
    } else if (isBrowser()) {
      alert("Invalid OTP");
    }
  };

  const removeContact = (id: string): void => {
    const updated = contacts.filter((current) => current.id !== id);

    setContacts(updated);

    safeStorage.set("trusted_contacts", JSON.stringify(updated));
  };

  return (
    <div className="space-y-3">
      <h4 className="font-bold text-red-500">Trusted Contacts</h4>

      <div className="flex gap-2">
        <input
          type="text"
          placeholder="Name"
          value={name}
          onChange={(event) => setName(event.target.value)}
          className="flex-1 bg-black border border-red-600 rounded px-2 py-1 text-sm text-white"
        />

        <input
          type="tel"
          placeholder="Phone"
          value={phone}
          onChange={(event) => setPhone(event.target.value)}
          className="flex-1 bg-black border border-red-600 rounded px-2 py-1 text-sm text-white"
        />

        <button
          type="button"
          onClick={() => void addContact()}
          className="bg-red-600 px-3 py-1 rounded-full text-sm text-white"
        >
          Add
        </button>
      </div>

      {contacts.map((contact) => (
        <div
          key={contact.id}
          className="bg-black border border-red-600 p-2 rounded-lg flex justify-between items-center"
        >
          <div>
            <div className="text-sm font-bold text-white">{contact.name}</div>

            <div className="text-xs text-white">{contact.phone}</div>

            {contact.verified && <span className="text-xs text-red-500">✓ Verified</span>}
          </div>

          {!contact.verified ? (
            verifyingId === contact.id ? (
              <div className="flex gap-1">
                <input
                  type="text"
                  placeholder="OTP"
                  value={otp}
                  onChange={(event) => setOtp(event.target.value)}
                  className="w-16 bg-black border border-red-600 rounded px-1 text-xs text-white"
                />

                <button
                  type="button"
                  onClick={() => void verifyContact(contact.id)}
                  className="bg-red-600 px-2 py-1 rounded text-xs text-white"
                >
                  Verify
                </button>
              </div>
            ) : (
              <button
                type="button"
                onClick={() => setVerifyingId(contact.id)}
                className="text-red-500 text-xs"
              >
                Verify
              </button>
            )
          ) : (
            <button
              type="button"
              onClick={() => removeContact(contact.id)}
              className="text-red-500 text-xs"
            >
              Remove
            </button>
          )}
        </div>
      ))}
    </div>
  );
}

