// ------------------------------
// SECTION: Haptics Helper
// ------------------------------
function useHaptics() {
  const shortPulse = () => {
    if (typeof navigator !== "undefined" && navigator.vibrate) {
      navigator.vibrate(50);
    }
  };
  const longPulse = () => {
    if (typeof navigator !== "undefined" && navigator.vibrate) {
      navigator.vibrate(200);
    }
  };
  return { shortPulse, longPulse };
}

// ------------------------------
// SECTION: PIN Lockout Logic (usePinLockout)
// ------------------------------
const MAX_ATTEMPTS = 5;
const LOCKOUT_DURATION_MS = 30 * 1000;

export function usePinLockout() {
  const [pinState, setPinState] = useState<PinState>(() => {
    if (typeof window === "undefined") return { attempts: 0, lockedUntil: null };
    const stored = localStorage.getItem("witness_pinState");
    if (stored) {
      const parsed = JSON.parse(stored);
      if (parsed.lockedUntil && parsed.lockedUntil > Date.now()) return parsed;
    }
    return { attempts: 0, lockedUntil: null };
  });
  const [remainingSeconds, setRemainingSeconds] = useState(0);

  const resetAttempts = useCallback(() => {
    const newState = { attempts: 0, lockedUntil: null };
    setPinState(newState);
    localStorage.setItem("witness_pinState", JSON.stringify(newState));
    setRemainingSeconds(0);
  }, []);

  const recordFailedAttempt = useCallback(() => {
    if (pinState.lockedUntil && pinState.lockedUntil > Date.now()) return;
    const newAttempts = pinState.attempts + 1;
    if (newAttempts >= MAX_ATTEMPTS) {
      const lockedUntil = Date.now() + LOCKOUT_DURATION_MS;
      const newState = { attempts: 0, lockedUntil };
      setPinState(newState);
      localStorage.setItem("witness_pinState", JSON.stringify(newState));
      setRemainingSeconds(LOCKOUT_DURATION_MS / 1000);
    } else {
      const newState = { ...pinState, attempts: newAttempts };
      setPinState(newState);
      localStorage.setItem("witness_pinState", JSON.stringify(newState));
    }
  }, [pinState]);

  const isLocked = pinState.lockedUntil !== null && pinState.lockedUntil > Date.now();

  useEffect(() => {
    if (!isLocked) return;
    const interval = setInterval(() => {
      const remaining = Math.max(0, Math.ceil((pinState.lockedUntil! - Date.now()) / 1000));
      setRemainingSeconds(remaining);
      if (remaining <= 0) {
        resetAttempts();
        clearInterval(interval);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [isLocked, pinState.lockedUntil, resetAttempts]);

  return { isLocked, remainingSeconds, recordFailedAttempt, resetAttempts };
}

// ------------------------------
// SECTION: Session Auto-Lock (useSessionTimeout)
// ------------------------------
const INACTIVITY_TIMEOUT_MS = 10 * 60 * 1000;

export function useSessionTimeout(onLock: () => void) {
  const timeoutRef = useRef<number | null>(null);
  const resetTimer = useCallback(() => {
    if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
    timeoutRef.current = window.setTimeout(() => {
      onLock();
    }, INACTIVITY_TIMEOUT_MS);
  }, [onLock]);

  useEffect(() => {
    const events = ["mousemove", "keydown", "touchstart", "click"];
    const handleActivity = () => resetTimer();
    events.forEach((ev) => window.addEventListener(ev, handleActivity));
    resetTimer();
    return () => {
      events.forEach((ev) => window.removeEventListener(ev, handleActivity));
      if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
    };
  }, [resetTimer]);
}

