export function ForgotPin({ onVerified }: { onVerified: (newPin: string) => void }) {
  const [step, setStep] = useState<"email" | "token" | "newPin">("email");
  const [email, setEmail] = useState("");
  const [token, setToken] = useState("");
  const [newPin, setNewPin] = useState("");
  const [error, setError] = useState("");
  const { shortPulse } = useHaptics();

  const sendVerification = async () => {
    const { error } = await supabaseMock.auth.signInWithOtp({ email });
    if (error) setError("Failed to send code");
    else setStep("token");
  };

  const verifyToken = async () => {
    const { error } = await supabaseMock.auth.verifyOtp({ email, token });
    if (error) setError("Invalid code");
    else setStep("newPin");
  };

  const submitNewPin = () => {
    if (!/^\d{4}$/.test(newPin)) {
      setError("PIN must be 4 digits");
      return;
    }
    shortPulse();
    onVerified(newPin);
  };

  return (
    <div className="bg-zinc-900 p-6 rounded-xl border border-zinc-800 border-l-4 border-l-red-600">
      <h3 className="text-xl font-black text-red-600 mb-4 uppercase italic">Recover Access</h3>
      {step === "email" && (
        <div className="space-y-3">
          <input
            type="email"
            placeholder="Authorized email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-3 text-white outline-none focus:border-red-600 transition-colors"
          />
          {error && <p className="text-red-500 text-xs font-bold uppercase italic">{error}</p>}
          <button
            onClick={sendVerification}
            className="bg-red-600 hover:bg-red-700 text-white font-black py-2 px-6 rounded-full w-full transition-all"
          >
            Dispatch Code
          </button>
        </div>
      )}
      {step === "token" && (
        <div className="space-y-3">
          <input
            type="text"
            placeholder="6-digit code"
            value={token}
            onChange={(e) => setToken(e.target.value)}
            className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-3 text-white text-center tracking-[0.5em] font-mono outline-none focus:border-red-600 transition-colors"
          />
          <button
            onClick={verifyToken}
            className="bg-red-600 hover:bg-red-700 text-white font-black py-2 px-6 rounded-full w-full transition-all"
          >
            Verify Identity
          </button>
        </div>
      )}
      {step === "newPin" && (
        <div className="space-y-3">
          <input
            type="password"
            maxLength={4}
            placeholder="New 4-digit PIN"
            value={newPin}
            onChange={(e) => setNewPin(e.target.value)}
