});

export const useTestSos = () => useContext(TestSosContext);

export function TestSosProvider({ children }: { children: React.ReactNode }) {
  const [testMode, setTestMode] = useState(false);
  const toggleTestMode = () => setTestMode((prev) => !prev);
  return (
    <TestSosContext.Provider value={{ testMode, toggleTestMode }}>
