      </div>
      <div className="flex items-center gap-5 relative z-10">
        <div
          className={`p-4 rounded-2xl bg-black border ${verified ? "border-red-600 shadow-[0_0_15px_rgba(232,0,28,0.2)]" : "border-zinc-800"}`}
