// WitnessEvidenceForensics.tsx
// Self-contained TypeScript React shell for evidence forensics.
// Implements chain of custody, admissibility scorer, court filing assistant,
// incident report generator, synchronized GPS timeline, forensic frame analysis,
// source verification engine, attorney-client privilege, broadcast export,
// one-tap evidence bundle. Uses Tailwind CSS, jsPDF, JSZip.

import React, { useState, useEffect, useCallback, useRef } from "react";
import { jsPDF } from "jspdf";
import JSZip from "jszip";

// ------------------------------
// SECTION: Types & Interfaces
// ------------------------------
export interface HashLogEntry {
  id: string;
  event: string;
  timestamp: number;
  previousHash: string;
  hash: string;
  details?: string;
}

export interface EvidenceScore {
  score: number;
  grade: "Poor" | "Fair" | "Good" | "Excellent";
  factors: {
    gpsLock: number;
    hashVerification: number;
    metadataComplete: number;
    lightingClarity: number;
  };
}

export interface IncidentReport {
  id: string;
  title: string;
  summary: string;
  victimInfo: string;
  officerBadges: string[];
  recordingIds: string[];
  createdAt: number;
}

export interface Recording {
  id: string;
  title: string;
  duration: number;
  timestamp: number;
  gps: { lat: number; lng: number };
  gpsTimeline: { time: number; lat: number; lng: number }[];
}

// Helper: SHA-256
const computeSha256 = async (input: string): Promise<string> => {
  const encoder = new TextEncoder();
  const data = encoder.encode(input);
  const hashBuffer = await crypto.subtle.digest("SHA-256", data);
  return Array.from(new Uint8Array(hashBuffer))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
};

