// ------------------------------
// SECTION: Tamper-Proof Chain of Custody (useChainOfCustody)
// ------------------------------
export function useChainOfCustody(recordingId: string) {
  const [chain, setChain] = useState<HashLogEntry[]>([]);
  const [isVerified, setIsVerified] = useState(true);

  const addEvent = useCallback(
    async (eventName: string, details?: string) => {
      let lastHash = "0";
      setChain((currentChain) => {
        if (currentChain.length > 0) {
          lastHash = currentChain[currentChain.length - 1].hash;
        }
        return currentChain;
      });

      const timestamp = Date.now();
      const rawString = `${eventName}|${timestamp}|${recordingId}|${lastHash}`;
      const hash = await computeSha256(rawString);

      const newEntry: HashLogEntry = {
        id: `${recordingId}_${timestamp}`,
        event: eventName,
        timestamp,
        previousHash: lastHash,
        hash,
        details,
      };

      setChain((prev) => [...prev, newEntry]);
      return newEntry;
    },
    [recordingId],
  );

  const verifyChain = useCallback(async () => {
    for (let i = 0; i < chain.length; i++) {
      const entry = chain[i];
      const raw = `${entry.event}|${entry.timestamp}|${recordingId}|${entry.previousHash}`;
      const computedHash = await computeSha256(raw);

      if (computedHash !== entry.hash) {
        setIsVerified(false);
        return false;
      }
      if (i > 0 && entry.previousHash !== chain[i - 1].hash) {
        setIsVerified(false);
        return false;
      }
    }
    setIsVerified(true);
    return true;
  }, [chain, recordingId]);

  useEffect(() => {
    if (chain.length === 0) {
      addEvent("Created");
    }
  }, [addEvent, chain.length]);

  return { chain, addEvent, verifyChain, isVerified };
}

// ------------------------------
// SECTION: Evidence Admissibility Scorer (AdmissibilityChecker)
// ------------------------------
export function AdmissibilityChecker({ recording }: { recording: Recording }) {
  const [score, setScore] = useState<EvidenceScore | null>(null);

  const calculateScore = () => {
    const gpsLock = recording.gps ? 85 : 0;
    const hashVerification = 90;
    const metadataComplete = recording.title ? 100 : 50;
    const lightingClarity = 70;
    const total = Math.floor((gpsLock + hashVerification + metadataComplete + lightingClarity) / 4);

    let grade: EvidenceScore["grade"] = "Poor";
    if (total >= 80) grade = "Excellent";
    else if (total >= 60) grade = "Good";
    else if (total >= 40) grade = "Fair";

    setScore({
      score: total,
      grade,
      factors: { gpsLock, hashVerification, metadataComplete, lightingClarity },
    });
  };

  return (
    <div className="bg-zinc-900 p-4 rounded-xl border-l-4 border-red-600 text-white shadow-lg">
      <h3 className="font-bold text-red-600 mb-2 uppercase tracking-wider">Admissibility Score</h3>
      <button
        onClick={calculateScore}
        className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-full text-sm mb-4 transition-colors font-bold uppercase"
      >
        Score Recording
      </button>
      {score && (
        <div className="animate-in fade-in slide-in-from-top-1">
          <div className="text-3xl font-black text-white">{score.score}%</div>
          <div className="text-sm font-bold text-red-500 mb-2">Grade: {score.grade}</div>
          <div className="grid grid-cols-2 gap-2 text-[10px] uppercase text-zinc-400 font-mono">
            <div>GPS: {score.factors.gpsLock}</div>
            <div>Hash: {score.factors.hashVerification}</div>
            <div>Metadata: {score.factors.metadataComplete}</div>
            <div>Lighting: {score.factors.lightingClarity}</div>
          </div>
        </div>
      )}
    </div>
  );
}

