// ------------------------------
// SECTION: Synchronized GPS Timeline (GpsOverlay)
// ------------------------------
export function GpsOverlay({
  videoRef,
  gpsData,
}: {
  videoRef: React.RefObject<HTMLVideoElement | null>;
  gpsData: { time: number; lat: number; lng: number }[];
}) {
  const [currentCoord, setCurrentCoord] = useState<string>("WAITING FOR GPS...");

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleTimeUpdate = () => {
      const currentTime = video.currentTime;
      // Find the closest previous or current point
      const point = [...gpsData].reverse().find((p) => p.time <= currentTime);
      if (point) {
        setCurrentCoord(`${point.lat.toFixed(5)}, ${point.lng.toFixed(5)}`);
      }
    };

    video.addEventListener("timeupdate", handleTimeUpdate);
    return () => video.removeEventListener("timeupdate", handleTimeUpdate);
  }, [gpsData, videoRef]);

  return (
    <div className="absolute bottom-16 right-4 bg-black/80 border border-red-600/50 text-white text-[10px] px-3 py-1.5 rounded-lg flex items-center gap-2 font-mono">
      <span className="text-red-600 animate-pulse">📍</span> {currentCoord}
    </div>
  );
}

// ------------------------------
// SECTION: Forensic Frame Analysis & Annotations (ForensicAnalyzer)
// ------------------------------
export function ForensicAnalyzer({ videoUrl }: { videoUrl: string }) {
  const [frame, setFrame] = useState(0);
  const [totalFrames, setTotalFrames] = useState(0);
  const [annotation, setAnnotation] = useState("");
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const captureFrame = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    canvas.width = video.videoWidth || 640;
    canvas.height = video.videoHeight || 360;
    ctx.drawImage(video, 0, 0);

    if (annotation) {
      ctx.font = "bold 24px sans-serif";
      ctx.fillStyle = "#FF0000";
      ctx.strokeStyle = "#000000";
      ctx.lineWidth = 2;
      ctx.strokeText(annotation, 50, 50);
      ctx.fillText(annotation, 50, 50);
    }
  }, [annotation]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    video.src = videoUrl;
    video.onloadedmetadata = () => setTotalFrames(Math.floor(video.duration * 30));
  }, [videoUrl]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    video.currentTime = frame / 30;
    const seekHandler = () => captureFrame();
    video.addEventListener("seeked", seekHandler);
    return () => video.removeEventListener("seeked", seekHandler);
  }, [frame, captureFrame]);

  return (
    <div className="bg-zinc-900 p-6 rounded-xl text-white shadow-xl space-y-4">
      <h3 className="font-bold text-red-600 uppercase tracking-wider">Forensic Frame Analyzer</h3>
      <video ref={videoRef} className="hidden" muted playsInline />
      <div className="bg-black rounded-lg border border-zinc-800 overflow-hidden aspect-video flex items-center justify-center">
        <canvas ref={canvasRef} className="max-w-full max-h-full" />
      </div>
      <div className="flex items-center justify-between gap-4 bg-black p-3 rounded-lg border border-zinc-800">
        <button
          onClick={() => setFrame(Math.max(0, frame - 1))}
          className="bg-zinc-800 hover:bg-zinc-700 p-2 rounded text-xs font-bold"
        >
          PREV
        </button>
        <span className="font-mono text-sm">
          FRAME: {frame} / {totalFrames}
        </span>
        <button
          onClick={() => setFrame(Math.min(totalFrames - 1, frame + 1))}
          className="bg-zinc-800 hover:bg-zinc-700 p-2 rounded text-xs font-bold"
        >
          NEXT
        </button>
      </div>
      <div className="flex gap-2">
        <input
          type="text"
          placeholder="Add forensic overlay text..."
          value={annotation}
          onChange={(e) => setAnnotation(e.target.value)}
          className="flex-grow bg-black border border-zinc-800 focus:border-red-600 rounded px-4 py-2 text-sm outline-none"
        />
        <button
          onClick={captureFrame}
          className="bg-red-600 hover:bg-red-700 px-6 py-2 rounded-full text-xs font-black uppercase tracking-tighter"
        >
          Overlay
        </button>
      </div>
    </div>
  );
}

