// ------------------------------
// SECTION: One-Tap Evidence Bundle (EvidencePackageBundle)
// ------------------------------
export function EvidencePackageBundle({
  recording,
  hashChain,
}: {
  recording: Recording;
  hashChain: HashLogEntry[];
}) {
  const [isBundling, setIsBundling] = useState(false);

  const bundle = async () => {
    setIsBundling(true);
    try {
      const zip = new JSZip();
      zip.file("recording_manifest.json", JSON.stringify(recording));

      const doc = new jsPDF();
      doc.text("Witness Evidence Certificate", 20, 30);
      doc.text(`Hash: ${recording.id}`, 20, 40);
      const pdfBlob = doc.output("blob");
      zip.file("certificate.pdf", pdfBlob);

      const chainText = hashChain
        .map((e) => `[${new Date(e.timestamp).toISOString()}] ${e.event} - HASH: ${e.hash}`)
        .join("\n");
      zip.file("chain_of_custody.txt", chainText);

      const content = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(content);
      const a = document.createElement("a");
      a.href = url;
      a.download = `witness_bundle_${recording.id}.zip`;
      a.click();
      URL.revokeObjectURL(url);
    } catch (e) {
      console.error(e);
    } finally {
      setIsBundling(false);
    }
  };

  return (
    <div className="bg-zinc-900 p-6 rounded-xl border-l-4 border-red-600 text-white shadow-lg text-center">
      <h3 className="font-black text-red-600 uppercase tracking-widest text-sm mb-4">
        Tactical Evidence Bundle
      </h3>
      <button
        onClick={bundle}
        disabled={isBundling}
        className="bg-red-600 hover:bg-red-700 disabled:bg-zinc-800 text-white px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all shadow-xl"
      >
        {isBundling ? "Processing Chain..." : "Generate ZIP Archive"}
      </button>
    </div>
  );
}

