const REPORT_STORAGE_KEY = "witness_incident_reports";

const genId = (): string => {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
};

function safeLoadReports(): IncidentReport[] {
  try {
    const stored = localStorage.getItem(REPORT_STORAGE_KEY);

    if (!stored) {
      return [];
    }

    return JSON.parse(stored) as IncidentReport[];
  } catch {
    return [];
  }
}

function saveReports(reports: IncidentReport[]): void {
  localStorage.setItem(REPORT_STORAGE_KEY, JSON.stringify(reports));
}

// ------------------------------
// SECTION: Incident Reporting (ReportGenerator)
// ------------------------------
export function useIncidentReporter() {
  const [reports, setReports] = useState<IncidentReport[]>(safeLoadReports);

  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [groupMode, setGroupMode] = useState(false);
  const [reportTitle, setReportTitle] = useState("");
  const [reportDesc, setReportDesc] = useState("");

  useEffect(() => {
    saveReports(reports);
  }, [reports]);

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((item) => item !== id) : [...prev, id],
    );
  };

  const createReport = () => {
    if (selectedIds.length === 0) {
      return;
    }

    const newReport: IncidentReport = {
      id: genId(),
      title: reportTitle.trim() || `Incident ${new Date().toLocaleDateString()}`,
      description: reportDesc.trim(),
      recordingIds: selectedIds,
      createdAt: Date.now(),
    };

    setReports((prev) => [newReport, ...prev]);

    setSelectedIds([]);
    setGroupMode(false);
    setReportTitle("");
    setReportDesc("");
  };

  const exportCSV = (report: IncidentReport) => {
    const selectedRecordings = mockRecordings.filter((recording) =>
      report.recordingIds.includes(recording.id),
    );

    const headers = [
      "Title",
      "Date",
      "Category",
      "Latitude",
      "Longitude",
      "Views",
      "Duration",
      "Status",
    ];

    const rows = selectedRecordings.map((recording) => [
      recording.title,
      recording.date,
      recording.category,
      recording.gps.lat.toString(),
      recording.gps.lng.toString(),
      recording.views.toString(),
      recording.duration.toString(),
      recording.status,
    ]);

    const csvContent = [headers, ...rows].map((row) => row.join(",")).join("\n");

    const blob = new Blob([csvContent], {
      type: "text/csv;charset=utf-8;",
    });

    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");

    link.href = url;
    link.download = `${report.title.replace(/\s+/g, "_")}.csv`;

    document.body.appendChild(link);

    link.click();

    document.body.removeChild(link);

    URL.revokeObjectURL(url);
  };

  return {
    reports,
    selectedIds,
    groupMode,
    setGroupMode,
    reportTitle,
    setReportTitle,
    reportDesc,
    setReportDesc,
    toggleSelect,
    createReport,
    exportCSV,
  };
}

