export function useHeatmapData() {
  const [dateRange, setDateRange] = useState<{
    from: string;
    to: string;
  }>({
    from: "",
    to: "",
  });

  const [category, setCategory] = useState<string>("all");

  const [filtered, setFiltered] = useState<Recording[]>(mockRecordings);

  useEffect(() => {
    let results = [...mockRecordings];

    if (dateRange.from) {
      results = results.filter((recording) => recording.date >= dateRange.from);
    }

    if (dateRange.to) {
      results = results.filter((recording) => recording.date <= dateRange.to);
    }

    if (category !== "all") {
      results = results.filter((recording) => recording.category === category);
    }

    setFiltered(results);
  }, [dateRange, category]);

  const categories = Array.from(new Set(mockRecordings.map((recording) => recording.category)));

  const HeatmapCanvas = () => {
    const canvasRef = useRef<HTMLCanvasElement | null>(null);

    useEffect(() => {
      const canvas = canvasRef.current;

      if (!canvas) {
        return;
      }

      const ctx = canvas.getContext("2d");

      if (!ctx) {
        return;
      }

      canvas.width = 500;
      canvas.height = 300;

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      filtered.forEach((recording) => {
        const x = ((recording.gps.lng + 74.02) / 0.08) * canvas.width;

        const y = ((40.73 - recording.gps.lat) / 0.06) * canvas.height;

        const intensity = Math.min(1, recording.views / 2000);

        const radius = 10 + intensity * 24;

        ctx.beginPath();

        ctx.arc(x, y, radius, 0, 2 * Math.PI);

        ctx.fillStyle = `rgba(255,0,0,${0.25 + intensity * 0.6})`;

        ctx.fill();
      });
    }, [filtered]);

    return (
      <canvas
        ref={canvasRef}
        width={500}
        height={300}
        className="w-full bg-black border border-red-600 rounded-lg"
      />
    );
  };

  return {
    dateRange,
    setDateRange,
    category,
    setCategory,
    categories,
    filtered,
    HeatmapCanvas,
  };
}

