// WitnessErrorHandling.tsx
// Self-contained TypeScript React shell for error handling & resilience.
// Implements: global crash boundary, smart network retry (exponential backoff),
// permission denied fallbacks (camera/mic/gps), offline upload queue,
// Supabase local-only mode, recording recovery engine, storage quota monitor.
// Uses Tailwind CSS, React hooks, useReducer. Exports all components/hooks.
// MainApp demo with tabs (Capture, Vault, System Health) and simulation buttons.

import React, {
  useState,
  useEffect,
  useCallback,
  useReducer,
  createContext,
  useContext,
} from "react";
import type { JSX } from "react";

// ------------------------------
// SECTION: Types & Interfaces
// ------------------------------
export interface ErrorLog {
  id: string;
  message: string;
  timestamp: number;
  componentStack?: string;
}

export interface UploadQueueItem {
  id: string;
  fileName: string;
  fileType: string;
  metadata: Record<string, unknown>;
  retryCount: number;
  lastAttempt: number;
}

export interface StorageEstimate {
  quota: number;
  usage: number;
  availableMB: number;
  percentageUsed: number;
}

export interface NetworkState {
  isOnline: boolean;
  isLocalOnly: boolean;
  syncPending: boolean;
}

export interface RecoverySession {
  sessionId: string;
  startedAt: number;
  lastChunkAt: number;
  chunkCount: number;
  totalBytes: number;
  mimeType: string;
}

type NetworkAction =
  | { type: "SET_ONLINE"; payload: boolean }
  | { type: "SET_LOCAL_ONLY"; payload: boolean }
  | { type: "SET_SYNC_PENDING"; payload: boolean };

const networkReducer = (state: NetworkState, action: NetworkAction): NetworkState => {
  switch (action.type) {
    case "SET_ONLINE":
      return { ...state, isOnline: action.payload };

    case "SET_LOCAL_ONLY":
      return { ...state, isLocalOnly: action.payload };

    case "SET_SYNC_PENDING":
      return { ...state, syncPending: action.payload };

    default:
      return state;
  }
};

// ------------------------------
// SECTION: Browser Helpers
// ------------------------------
const isBrowser = (): boolean => typeof window !== "undefined";

const safeLocalStorage = {
  get(key: string): string | null {
    if (!isBrowser()) return null;

    try {
      return window.localStorage.getItem(key);
    } catch {
      return null;
    }
  },

  set(key: string, value: string): void {
    if (!isBrowser()) return;

    try {
      window.localStorage.setItem(key, value);
    } catch (error) {
      console.error("localStorage set failed:", error);
    }
  },

  remove(key: string): void {
    if (!isBrowser()) return;

    try {
      window.localStorage.removeItem(key);
    } catch (error) {
      console.error("localStorage remove failed:", error);
    }
  },
};

// ------------------------------
// SECTION: Utility Functions
// ------------------------------
const genId = (): string => `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

// ------------------------------
// SECTION 1: GLOBAL CRASH BOUNDARY
// ------------------------------
interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  errorInfo: React.ErrorInfo | null;
}

export class WitnessErrorBoundary extends React.Component<
  { children: React.ReactNode },
  ErrorBoundaryState
> {
  constructor(props: { children: React.ReactNode }) {
    super(props);

    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
    };
  }

  static getDerivedStateFromError(error: Error) {
    return {
      hasError: true,
      error,
    };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo): void {
    this.setState({ errorInfo });

    console.error("Global crash:", error, errorInfo);
  }

  softReset = (): void => {
    safeLocalStorage.remove("app_crash_state");

    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
    });

    if (isBrowser()) {
      window.location.reload();
    }
  };

  render(): React.ReactNode {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-black flex items-center justify-center p-4">
          <div className="bg-black border border-red-600 rounded-xl p-6 max-w-md w-full">
            <h2 className="text-2xl font-bold text-red-500 mb-2">System Recovery</h2>

            <p className="text-sm text-white mb-4">
              The application encountered an unexpected error.
            </p>

            <div className="bg-neutral-950 border border-red-600 rounded-lg p-3 mb-4 overflow-auto max-h-40">
              <p className="text-xs text-red-400 font-mono">{this.state.error?.message}</p>

              {this.state.errorInfo && (
                <pre className="text-xs text-white mt-2 whitespace-pre-wrap">
                  {this.state.errorInfo.componentStack?.slice(0, 400)}
                </pre>
              )}
            </div>

            <button
              type="button"
              onClick={this.softReset}
              className="w-full bg-red-600 hover:bg-red-700 transition-colors py-2 rounded-full font-bold text-white"
            >
              Soft Reset App
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

// ------------------------------
// SECTION 2: SMART NETWORK RETRY HOOK
// ------------------------------
export function useNetworkRequest() {
  const [isOnline, setIsOnline] = useState<boolean>(() => (isBrowser() ? navigator.onLine : true));

  useEffect(() => {
    if (!isBrowser()) return;

    const handleOnline = (): void => setIsOnline(true);
    const handleOffline = (): void => setIsOnline(false);

    window.addEventListener("online", handleOnline);
    window.addEventListener("offline", handleOffline);

    return () => {
      window.removeEventListener("online", handleOnline);

      window.removeEventListener("offline", handleOffline);
    };
  }, []);

  const requestWithRetry = useCallback(
    async <T,>(requestFn: () => Promise<T>, maxRetries = 3, baseDelay = 1000): Promise<T> => {
      if (!isOnline) {
        throw new Error("No network connection. Request pending.");
      }

      let lastError: Error | null = null;

      for (let attempt = 0; attempt < maxRetries; attempt++) {
        try {
          return await requestFn();
        } catch (error) {
          lastError = error instanceof Error ? error : new Error("Unknown request failure");

          if (attempt >= maxRetries - 1) {
            break;
          }

          const delay = baseDelay * Math.pow(2, attempt);

          await new Promise((resolve) => setTimeout(resolve, delay));
        }
      }

      throw lastError ?? new Error("Request failed after retries");
    },
    [isOnline],
  );

  return {
    requestWithRetry,
    isOnline,
  };
}

// ------------------------------
// SECTION 3: PERMISSION DENIED FALLBACKS
// ------------------------------
interface PermissionGuardProps {
  type: "camera" | "mic" | "gps";
  children: React.ReactNode;
  onFallback?: () => void;
}

export function PermissionGuard({ type, children, onFallback }: PermissionGuardProps): JSX.Element {
  const [permissionGranted, setPermissionGranted] = useState<boolean | null>(null);

  const [showFallback, setShowFallback] = useState<boolean>(false);

  useEffect(() => {
    let mounted = true;

    const checkPermissions = async (): Promise<void> => {
      if (!isBrowser()) {
        setPermissionGranted(false);
        return;
      }

      try {
        if (type === "camera" || type === "mic") {
          if (!navigator.mediaDevices?.getUserMedia) {
            throw new Error("Media devices unavailable");
          }

          const constraints = type === "camera" ? { video: true } : { audio: true };

          const stream = await navigator.mediaDevices.getUserMedia(constraints);

          stream.getTracks().forEach((track) => track.stop());

          if (mounted) {
            setPermissionGranted(true);
          }

          return;
        }

        if (type === "gps") {
          if (!navigator.geolocation) {
            throw new Error("Geolocation unavailable");
          }

          navigator.geolocation.getCurrentPosition(
            () => {
              if (mounted) {
                setPermissionGranted(true);
              }
            },
            (error) => {
              if (!mounted) return;

              if (error.code === 1) {
                setPermissionGranted(false);
                setShowFallback(true);
                onFallback?.();
              } else {
                setPermissionGranted(false);
              }
            },
          );
        }
      } catch (error) {
        console.error(error);

        if (!mounted) return;

        setPermissionGranted(false);
        setShowFallback(true);

        onFallback?.();
      }
    };

    void checkPermissions();

    return () => {
      mounted = false;
    };
  }, [type, onFallback]);

  if (permissionGranted === null) {
    return <div className="text-center text-white py-4">Checking permissions...</div>;
  }

  if (showFallback) {
    if (type === "camera" || type === "mic") {
      return (
        <div className="bg-black border border-red-600 rounded-xl p-4 text-center">
          <p className="text-red-500 font-bold mb-2">{type.toUpperCase()} Access Denied</p>

          <p className="text-sm text-white mb-3">Manual upload mode enabled.</p>

          <input
            type="file"
            accept="video/*"
            className="bg-black border border-red-600 rounded px-3 py-1 text-sm text-white"
          />
        </div>
      );
    }

    return (
      <div className="bg-black border border-red-600 rounded-xl p-4">
        <p className="text-red-500 font-bold mb-2">GPS Access Denied</p>

        <p className="text-sm text-white mb-3">Enter your address manually:</p>

        <input
          type="text"
          placeholder="Street, City, ZIP"
          className="w-full bg-black border border-red-600 rounded px-3 py-2 text-white text-sm"
        />
      </div>
    );
  }

  return <>{children}</>;
}

// ------------------------------
// SECTION 4: OFFLINE UPLOAD QUEUE
// ------------------------------
export function useUploadManager() {
  const [queue, setQueue] = useState<UploadQueueItem[]>(() => {
    const stored = safeLocalStorage.get("upload_queue");

    if (!stored) return [];

    try {
      return JSON.parse(stored) as UploadQueueItem[];
    } catch {
      return [];
    }
  });

  const { isOnline, requestWithRetry } = useNetworkRequest();

  useEffect(() => {
    safeLocalStorage.set("upload_queue", JSON.stringify(queue));
  }, [queue]);

  const addToQueue = useCallback((file: File, metadata: Record<string, unknown>): void => {
    const newItem: UploadQueueItem = {
      id: genId(),
      fileName: file.name,
      fileType: file.type,
      metadata,
      retryCount: 0,
      lastAttempt: Date.now(),
    };

    setQueue((prev) => [newItem, ...prev]);
  }, []);

  const processQueue = useCallback(async (): Promise<void> => {
    if (!isOnline) return;

    for (const item of queue) {
      try {
        await requestWithRetry(async () => {
          await new Promise((resolve) => setTimeout(resolve, 500));

          return true;
        });

        setQueue((prev) => prev.filter((i) => i.id !== item.id));
      } catch (error) {
        console.error(`Upload failed for ${item.fileName}`, error);

        setQueue((prev) =>
          prev.map((i) =>
            i.id === item.id
              ? {
                  ...i,
                  retryCount: i.retryCount + 1,
                  lastAttempt: Date.now(),
                }
              : i,
          ),
        );
      }
    }
  }, [isOnline, queue, requestWithRetry]);

  useEffect(() => {
    if (isOnline && queue.length > 0) {
      void processQueue();
    }
  }, [isOnline, queue.length, processQueue]);

  return {
    queue,
    addToQueue,
    processQueue,
  };
}

// ------------------------------
// SECTION 5: SUPABASE LOCAL-ONLY MODE
// ------------------------------
interface DatabaseContextValue {
  isLocalOnly: boolean;
  setLocalOnly: (mode: boolean) => void;
  syncRequired: boolean;
  markSynced: () => void;
}

const DatabaseContext = createContext<DatabaseContextValue | null>(null);

export function useDatabase() {
  const context = useContext(DatabaseContext);

  if (!context) {
    throw new Error("useDatabase must be used within SupabaseProvider");
  }

  return context;
}

export function SupabaseProvider({ children }: { children: React.ReactNode }): JSX.Element {
  const [networkState, dispatch] = useReducer(networkReducer, {
    isOnline: isBrowser() ? navigator.onLine : true,
    isLocalOnly: false,
    syncPending: false,
  });

  const [localOnly, setLocalOnly] = useState<boolean>(false);

  const [syncRequired, setSyncRequired] = useState<boolean>(false);

  const setLocalOnlyMode = (mode: boolean): void => {
    setLocalOnly(mode);

    dispatch({
      type: "SET_LOCAL_ONLY",
      payload: mode,
    });

    if (mode) {
      setSyncRequired(true);
    }
  };

  const markSynced = (): void => {
    setSyncRequired(false);

    dispatch({
      type: "SET_SYNC_PENDING",
      payload: false,
    });
  };

  useEffect(() => {
    let mounted = true;

    const initSupabase = async (): Promise<void> => {
      await new Promise((resolve) => setTimeout(resolve, 300));

      if (!mounted) return;

      const simulatedFailure = false;

      if (simulatedFailure) {
        setLocalOnlyMode(true);
      }
    };

    void initSupabase();

    return () => {
      mounted = false;
    };
  }, []);

  return (
    <DatabaseContext.Provider
      value={{
        isLocalOnly: localOnly,
        setLocalOnly: setLocalOnlyMode,
        syncRequired,
        markSynced,
      }}
    >
      {children}

      {networkState.isLocalOnly && (
        <div className="fixed top-20 right-4 bg-red-600 text-white px-3 py-1 rounded-full text-xs font-bold z-50">
          LOCAL-ONLY MODE
        </div>
      )}
    </DatabaseContext.Provider>
  );
}

// ------------------------------
// SECTION 6: RECORDING RECOVERY ENGINE (REAL)
// ------------------------------
// Scans the actual Witness IndexedDB recording session stores for incomplete
// sessions (recordings that were interrupted by a crash, battery death, or OS
// tab kill) and allows the user to recover them.
//
// This replaces the previous fake recovery that created a Blob from JSON metadata.

const WITNESS_DB = "WitnessDB";
const RECORDING_SESSIONS = "recording-sessions";
const RECORDING_CHUNKS = "recording-chunks";
const FINALIZED = "recordings";

async function openWitnessDB(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(WITNESS_DB, 2);
    req.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(RECORDING_SESSIONS)) {
        db.createObjectStore(RECORDING_SESSIONS, { keyPath: "id" });
      }
      if (!db.objectStoreNames.contains(RECORDING_CHUNKS)) {
        const chunks = db.createObjectStore(RECORDING_CHUNKS, { keyPath: "id" });
        chunks.createIndex("sessionId", "sessionId", { unique: false });
      }
      if (!db.objectStoreNames.contains(FINALIZED)) {
        db.createObjectStore(FINALIZED, { keyPath: "id" });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

export function useRecordingRecovery() {
  const [recoverableSessions, setRecoverableSessions] = useState<RecoverySession[]>([]);
  const [isScanning, setIsScanning] = useState(false);

  const scanForRecovery = useCallback(async (): Promise<void> => {
    if (!isBrowser()) return;
    setIsScanning(true);
    try {
      const db = await openWitnessDB();
      const tx = db.transaction([RECORDING_SESSIONS, RECORDING_CHUNKS], "readonly");
      const sessionStore = tx.objectStore(RECORDING_SESSIONS);
      const chunkStore = tx.objectStore(RECORDING_CHUNKS);

      const sessions: RecoverySession[] = await new Promise((resolve, reject) => {
        const req = sessionStore.getAll();
        req.onsuccess = () => {
          const all = req.result as Array<{
            id: string;
            startedAt: number;
            lastChunkAt: number;
            chunkCount: number;
            totalBytes: number;
            mimeType: string;
            finalized?: boolean;
          }>;
          // Only sessions that have chunks but were never finalized.
          const incomplete = all
            .filter((s) => !s.finalized && s.chunkCount > 0)
            .map((s) => ({
              sessionId: s.id,
              startedAt: s.startedAt,
              lastChunkAt: s.lastChunkAt,
              chunkCount: s.chunkCount,
              totalBytes: s.totalBytes,
              mimeType: s.mimeType,
            }));
          resolve(incomplete);
        };
        req.onerror = () => reject(req.error);
      });

      // Cross-check: make sure chunks actually exist in the chunks store.
      const verified: RecoverySession[] = [];
      for (const s of sessions) {
        const index = chunkStore.index("sessionId");
        const countReq = index.count(s.sessionId);
        const actualCount = await new Promise<number>((resolve, reject) => {
          countReq.onsuccess = () => resolve(countReq.result);
          countReq.onerror = () => reject(countReq.error);
        });
        if (actualCount > 0) {
          verified.push({ ...s, chunkCount: actualCount });
        }
      }

      setRecoverableSessions(verified);
    } catch (err) {
      console.error("[witness-recovery] scan failed", err);
    } finally {
      setIsScanning(false);
    }
  }, []);

  const recoverSession = useCallback(async (sessionId: string): Promise<Blob | null> => {
    if (!isBrowser()) return null;
    try {
      const db = await openWitnessDB();
      const tx = db.transaction(RECORDING_CHUNKS, "readonly");
      const store = tx.objectStore(RECORDING_CHUNKS);
      const index = store.index("sessionId");
      const req = index.getAll(sessionId);

      const chunks = await new Promise<Array<{ id: string; blob: Blob; seq: number }>>(
        (resolve, reject) => {
          req.onsuccess = () => {
            const all = (req.result as Array<{ id: string; blob: Blob; seq: number }>).sort(
              (a, b) => a.seq - b.seq,
            );
            resolve(all);
          };
          req.onerror = () => reject(req.error);
        },
      );

      if (!chunks.length) return null;

      const recovered = new Blob(
        chunks.map((c) => c.blob),
        { type: chunks[0].blob.type || "video/webm" },
      );

      // Mark session as recovered so we don't offer it again.
      const writeTx = db.transaction(RECORDING_SESSIONS, "readwrite");
      const sessionStore = writeTx.objectStore(RECORDING_SESSIONS);
      const getReq = sessionStore.get(sessionId);
      await new Promise<void>((resolve, reject) => {
        getReq.onsuccess = () => {
          const data = getReq.result;
          if (data) {
            data.finalized = true;
            data.recoveredAt = Date.now();
            sessionStore.put(data);
          }
          resolve();
        };
        getReq.onerror = () => reject(getReq.error);
      });

      return recovered;
    } catch (err) {
      console.error("[witness-recovery] recoverSession failed", err);
      return null;
    }
  }, []);

  const discardSession = useCallback(async (sessionId: string): Promise<void> => {
    if (!isBrowser()) return;
    try {
      const db = await openWitnessDB();
      const tx = db.transaction([RECORDING_SESSIONS, RECORDING_CHUNKS], "readwrite");
      tx.objectStore(RECORDING_SESSIONS).delete(sessionId);

      const chunkStore = tx.objectStore(RECORDING_CHUNKS);
      const index = chunkStore.index("sessionId");
      const req = index.getAllKeys(sessionId);
      await new Promise<void>((resolve, reject) => {
        req.onsuccess = () => {
          for (const key of req.result) {
            chunkStore.delete(key);
          }
          resolve();
        };
        req.onerror = () => reject(req.error);
      });

      setRecoverableSessions((prev) => prev.filter((s) => s.sessionId !== sessionId));
    } catch (err) {
      console.error("[witness-recovery] discardSession failed", err);
    }
  }, []);

  useEffect(() => {
    void scanForRecovery();
  }, [scanForRecovery]);

  return {
    recoverableSessions,
    isScanning,
    scanForRecovery,
    recoverSession,
    discardSession,
  };
}

// ------------------------------
// SECTION 7: STORAGE QUOTA MONITOR
// ------------------------------
export function useStorageMonitor(thresholdMB = 500) {
  const [storageEstimate, setStorageEstimate] = useState<StorageEstimate | null>(null);

  const [isLow, setIsLow] = useState<boolean>(false);

  const updateEstimate = useCallback(async (): Promise<void> => {
    if (!isBrowser() || !navigator.storage?.estimate) {
      return;
    }

    try {
      const estimate = await navigator.storage.estimate();

      const usage = estimate.usage ?? 0;
      const quota = estimate.quota ?? 0;

      if (quota <= 0) return;

      const availableMB = (quota - usage) / (1024 * 1024);

      const percentageUsed = (usage / quota) * 100;

      setStorageEstimate({
        quota,
        usage,
        availableMB,
        percentageUsed,
      });

      setIsLow(availableMB < thresholdMB);
    } catch (error) {
      console.error("Storage estimate failed:", error);
    }
  }, [thresholdMB]);

  useEffect(() => {
    void updateEstimate();
  }, [updateEstimate]);

  return {
    storageEstimate,
    isLow,
    updateEstimate,
  };
}

export function StorageWarning({
  onClearCache,
}: {
  onClearCache?: () => void;
}): JSX.Element | null {
  const { isLow, storageEstimate } = useStorageMonitor();

  if (!isLow || !storageEstimate) {
    return null;
  }

  return (
    <div className="fixed bottom-20 left-4 right-4 bg-black border border-red-600 p-3 rounded-lg z-50">
      <div className="flex justify-between items-start">
        <div>
          <p className="text-red-500 font-bold text-sm">Low Storage Warning</p>

          <p className="text-xs text-white">
            {storageEstimate.availableMB.toFixed(0)} MB remaining
          </p>
        </div>

