function VaultTab(): JSX.Element {
  const { queue, processQueue } = useUploadManager();

  const { recoverableSessions, recoverSession, discardSession } = useRecordingRecovery();

  const { setLocalOnly, syncRequired, markSynced } = useDatabase();

  const handleRecover = async (sessionId: string) => {
    const blob = await recoverSession(sessionId);
    if (blob) {
      // In a real app this would feed into saveRecording() or offer download.
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `witness-recovered-${sessionId}.webm`;
      a.click();
      URL.revokeObjectURL(url);
    }
  };

  return (
    <div className="space-y-4">
      <div className="bg-black border border-red-600 rounded-xl p-4">
        <h3 className="font-bold text-red-500 mb-2">Upload Queue</h3>

