          <div
            key={item.id}
            className="bg-neutral-950 border border-red-600 rounded p-2 mb-2 text-sm flex justify-between"
          >
            <span>{item.fileName}</span>

            <span className="text-red-500">retry {item.retryCount}</span>
          </div>
