        <button
          type="button"
          onClick={() => {
            void processQueue();
          }}
          className="mt-2 bg-red-600 px-3 py-1 rounded-full text-xs text-white"
        >
          Process Queue
        </button>
      </div>

      {recoverableSessions.length > 0 && (
        <div className="bg-black border border-red-600 rounded-xl p-4">
          <h3 className="font-bold text-red-500 mb-2">
            Recoverable Sessions ({recoverableSessions.length})
          </h3>

          {recoverableSessions.map((session) => (
            <div
              key={session.sessionId}
              className="bg-neutral-950 border border-red-600 rounded p-2 mb-2 text-sm"
            >
              <div className="flex justify-between">
                <span>
                  {new Date(session.startedAt).toLocaleString()} · {session.chunkCount} chunks ·{" "}
                  {(session.totalBytes / 1024 / 1024).toFixed(1)} MB
                </span>
              </div>
              <div className="flex gap-2 mt-2">
                <button
                  type="button"
                  onClick={() => void handleRecover(session.sessionId)}
                  className="bg-red-600 px-3 py-1 rounded-full text-xs text-white"
