                  Recover
                </button>
                <button
                  type="button"
                  onClick={() => void discardSession(session.sessionId)}
                  className="bg-neutral-900 border border-red-600 px-3 py-1 rounded-full text-xs text-white"
                >
                  Discard
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <div className="bg-black border border-red-600 rounded-xl p-4">
        <h3 className="font-bold text-red-500 mb-2">Local-Only Mode</h3>

        <button
          type="button"
          onClick={() => setLocalOnly(true)}
          className="bg-neutral-900 border border-red-600 px-3 py-1 rounded-full text-xs text-white"
        >
          Enable Local-Only
        </button>

        {syncRequired && (
          <button
            type="button"
            onClick={markSynced}
            className="ml-2 bg-red-600 px-3 py-1 rounded-full text-xs text-white"
          >
            Mark Synced
          </button>
        )}
      </div>
    </div>
  );
}

