// ------------------------------
// SECTION: Onboarding Status Hook (useOnboardingStatus)
// ------------------------------
export function useOnboardingStatus() {
  const [progress, setProgress] = useState<OnboardingProgress>(() => {
    if (typeof window === "undefined")
      return {
        hasCompletedOnboarding: false,
        hasAcceptedLegal: false,
        hasSeenTutorial: false,
        lastVersionSeen: "",
        firstRecordingCelebrated: false,
      };
    const stored = localStorage.getItem("witness_onboarding_progress");
    if (stored) return JSON.parse(stored);
    return {
      hasCompletedOnboarding: false,
      hasAcceptedLegal: false,
      hasSeenTutorial: false,
      lastVersionSeen: "",
      firstRecordingCelebrated: false,
    };
  });

  const updateProgress = useCallback((updates: Partial<OnboardingProgress>) => {
    setProgress((prev) => {
      const newProgress = { ...prev, ...updates };
      localStorage.setItem("witness_onboarding_progress", JSON.stringify(newProgress));
      return newProgress;
    });
  }, []);

  const completeOnboarding = () => updateProgress({ hasCompletedOnboarding: true });
  const acceptLegal = () => updateProgress({ hasAcceptedLegal: true });
  const markTutorialSeen = () => updateProgress({ hasSeenTutorial: true });
  const celebrateFirstRecording = () => updateProgress({ firstRecordingCelebrated: true });
  const updateLastVersion = () => updateProgress({ lastVersionSeen: APP_VERSION });

  const showWhatsNew = progress.lastVersionSeen !== APP_VERSION && progress.hasCompletedOnboarding;

  return {
    progress,
    completeOnboarding,
    acceptLegal,
    markTutorialSeen,
    celebrateFirstRecording,
    updateLastVersion,
    showWhatsNew,
  };
}

// ------------------------------
// SECTION: The Welcome Journey (OnboardingSwiper)
// ------------------------------
export function OnboardingSwiper({ onComplete }: { onComplete: () => void }) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const touchStartX = useRef(0);
  const slides = [
    {
      title: "The Mission",
      description:
        "Witness R.E.P. is a civil rights tool designed to document, encrypt, and verify critical incidents.",
      icon: "🎯",
    },
    {
      title: "The Technology",
      description:
        "SHA-256 hashing, AES-256 encryption, and blockchain‑ready certificates ensure your evidence is tamper‑proof.",
      icon: "🔒",
    },
    {
      title: "The Protection",
      description: "Your recordings are yours alone. No ads, no paywalls, no data selling.",
      icon: "🛡️",
    },
  ];
  const slide = slides[currentIndex];

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const diff = e.changedTouches[0].clientX - touchStartX.current;
    if (Math.abs(diff) > 50) {
      if (diff > 0 && currentIndex > 0) setCurrentIndex(currentIndex - 1);
      else if (diff < 0 && currentIndex < slides.length - 1) setCurrentIndex(currentIndex + 1);
    }
  };

  const next = () => {
    if (currentIndex < slides.length - 1) setCurrentIndex(currentIndex + 1);
    else onComplete();
  };

  return (
    <div
      className="fixed inset-0 bg-black z-50 flex flex-col items-center justify-center p-6 text-white"
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
    >
      <div className="text-center max-w-md animate-in fade-in duration-500">
        <div className="text-8xl mb-8 drop-shadow-[0_0_15px_rgba(220,38,38,0.5)]" key={genId()}>
          {slide.icon}
        </div>
        <h2 className="text-4xl font-black mb-4 uppercase italic tracking-tighter text-red-600">
          {slide.title}
        </h2>
        <p className="text-zinc-400 text-lg leading-relaxed mb-8">{slide.description}</p>
        <div className="flex justify-center gap-3 mb-12">
          {slides.map((_, i) => (
            <div
              key={i}
              className={`h-1.5 rounded-full transition-all duration-300 ${i === currentIndex ? "bg-red-600 w-8" : "bg-zinc-800 w-2"}`}
            />
          ))}
        </div>
        <div className="flex gap-4 w-full">
          <button
            onClick={onComplete}
            className="flex-1 bg-zinc-900 border border-zinc-800 text-zinc-500 py-4 rounded-2xl font-bold uppercase text-xs tracking-widest hover:text-white transition-colors"
          >
            Skip
          </button>
          <button
            onClick={next}
            className="flex-1 bg-red-600 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg shadow-red-900/20 hover:bg-red-700 transition-all"
          >
            {currentIndex === slides.length - 1 ? "Initialize" : "Next"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ------------------------------
// SECTION: Permission Primer (PreFlightCheck)
// ------------------------------
export function PreFlightCheck({ onComplete }: { onComplete: () => void }) {
  const [step, setStep] = useState<"camera" | "mic" | "location">("camera");

  const requestCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      stream.getTracks().forEach((track) => track.stop());
      setStep("mic");
    } catch (err) {
      alert("Camera permission required. Please enable in device settings.");
    }
  };

  const requestMic = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach((track) => track.stop());
      setStep("location");
    } catch (err) {
      alert("Microphone permission required.");
    }
  };

  const requestLocation = () => {
    navigator.geolocation.getCurrentPosition(
      () => onComplete(),
      () => alert("Location permission required for GPS evidence."),
    );
  };

  return (
    <div className="fixed inset-0 bg-black z-50 flex items-center justify-center p-6 text-white">
      <div className="bg-zinc-950 p-8 rounded-3xl border border-zinc-900 border-l-4 border-l-red-600 max-w-md w-full shadow-2xl">
        <h2 className="text-2xl font-black text-red-600 mb-6 uppercase tracking-widest italic">
          System Access
        </h2>
        {step === "camera" && (
          <div className="animate-in slide-in-from-bottom-4 duration-300">
            <p className="text-zinc-400 mb-8 leading-relaxed">
              Witness R.E.P. requires visual sensor access to document incidents in real-time.
            </p>
            <button
              onClick={requestCamera}
              className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-4 rounded-2xl uppercase text-xs tracking-widest transition-all"
            >
              Enable Camera
            </button>
            <button
              onClick={onComplete}
              className="w-full mt-4 text-zinc-600 font-bold uppercase text-[10px] tracking-widest"
            >
              Skip for now
            </button>
          </div>
        )}
        {step === "mic" && (
          <div className="animate-in slide-in-from-bottom-4 duration-300">
            <p className="text-zinc-400 mb-8 leading-relaxed">
              Acoustic sensors capture critical verbal context alongside video evidence.
            </p>
            <button
              onClick={requestMic}
              className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-4 rounded-2xl uppercase text-xs tracking-widest transition-all"
            >
              Enable Audio
            </button>
          </div>
        )}
        {step === "location" && (
          <div className="animate-in slide-in-from-bottom-4 duration-300">
            <p className="text-zinc-400 mb-8 leading-relaxed">
              Spatial metadata timestamps your evidence for high-integrity legal verification.
            </p>
            <button
              onClick={requestLocation}
              className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-4 rounded-2xl uppercase text-xs tracking-widest transition-all"
            >
              Enable GPS
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

