// ------------------------------
export interface RecordingRecord {
  id: string;
  title: string;
  timestamp: number;
  category: string;
  thumbnailBlob?: Blob;
  duration: number;
}

export interface BufferChunk {
  id: string;
  data: Blob;
  timestamp: number;
  committed: boolean;
}

export interface MapCoordinate {
  lat: number;
  lng: number;
  id: string;
  intensity: number;
}

interface LazyVaultProps {
  onPerformanceUpdate?: (time: number) => void;
}

