// SECTION: Constants
// ------------------------------
const DB_NAME = "WitnessVaultDB";

const DB_VERSION = 1;

const STORE_NAME = "recordings";

// ------------------------------
// SECTION: Browser Helpers
// ------------------------------
function isBrowser(): boolean {
  return typeof window !== "undefined";
}

