// WitnessSilentSOS.tsx
import React, { useState, useEffect, useRef, useCallback } from "react";

// ------------------------------
// SECTION: TYPES & DB
// ------------------------------
const DB_NAME = "WitnessSilentDB";
const STORE_NAME = "recordings";

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, 1);
    req.onupgradeneeded = (e: any) =>
      e.target.result.createObjectStore(STORE_NAME, { keyPath: "id" });
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
};

// ------------------------------
// SECTION: MAIN COMPONENT
// ------------------------------
const WitnessSilentSOS: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [showConfirmDot, setShowConfirmDot] = useState(false);

  // Refs for background processing
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const encryptionKeyRef = useRef<CryptoKey | null>(null);
  const isActiveRef = useRef(false); // Used to avoid stale state in timeouts
  const tapCounts = useRef({ topLeft: 0, topRight: 0 });
  const gestureTimeout = useRef<NodeJS.Timeout | null>(null);

  // 1. Silent Notification (Haptic)
  const silentVibrate = (pattern: number | number[]) => {
    if (navigator.vibrate) navigator.vibrate(pattern);
  };

  // 2. Encryption Engine
  const initCrypto = async () => {
    encryptionKeyRef.current = await crypto.subtle.generateKey(
      { name: "AES-GCM", length: 256 },
      true,
      ["encrypt", "decrypt"],
    );
  };

  // 3. SOS Trigger Logic
  const triggerSOS = async () => {
    if (isActiveRef.current) return; // Prevent double-triggering

    isActiveRef.current = true;
    setIsActive(true);
    silentVibrate([100, 50, 100]); // Two tiny pulses only the user feels

    try {
      // A. Initialize Audio & Crypto
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      await initCrypto();

      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;

      recorder.ondataavailable = async (e) => {
        if (!e.data?.size || !encryptionKeyRef.current) return;
        try {
          const buffer = await e.data.arrayBuffer();
          const iv = crypto.getRandomValues(new Uint8Array(12));
          const encrypted = await crypto.subtle.encrypt(
            { name: "AES-GCM", iv },
            encryptionKeyRef.current,
            buffer,
          );

          const db = await openDB();
          const tx = db.transaction(STORE_NAME, "readwrite");
          await new Promise<void>((resolve, reject) => {
            const req = tx.objectStore(STORE_NAME).add({
              id: crypto.randomUUID(),
              data: encrypted,
              iv: iv,
              timestamp: Date.now(),
            });
            req.onsuccess = () => resolve();
            req.onerror = () => reject(req.error);
          });
        } catch (chunkErr) {
          // If encryption or IndexedDB fails, the chunk is lost.
          // At minimum log it so a future crash-report can surface the gap.
          console.error("[witness-silent-sos] chunk save failed", chunkErr);
          // Fallback: stash raw chunk to a fallback object store if available.
          try {
            const db = await openDB();
            const tx = db.transaction(STORE_NAME, "readwrite");
            tx.objectStore(STORE_NAME).add({
              id: crypto.randomUUID(),
              data: "raw-fallback",
              rawBlob: e.data,
              timestamp: Date.now(),
              fallback: true,
            });
          } catch {
            /* completely out of storage — nothing more we can do */
          }
        }
      };

      recorder.start(5000); // Save audio in 5-second chunks

      // B. GPS & SOS API (Simulated)
      navigator.geolocation.getCurrentPosition((pos) => {
        console.log("SILENT SOS: GPS Sent", pos.coords.latitude);
        // fetch("/api/sos/silent", { method: "POST", body: ... })
      });

      // C. Hidden Confirmation (Tiny red dot appears after 5s for 1s)
      setTimeout(() => {
        if (isActiveRef.current) {
          setShowConfirmDot(true);
          setTimeout(() => setShowConfirmDot(false), 1000);
        }
      }, 5000);
    } catch (err) {
      console.error("Silent SOS initialization failed", err);
      cancelSOS();
    }
  };

  // 4. Cancel Logic
  const cancelSOS = useCallback(() => {
    isActiveRef.current = false;
    setIsActive(false);
    silentVibrate(300); // One longer vibration to confirm "Safe" status

    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach((t) => t.stop());
    }
  }, []);

  // 5. Gesture Detection for Silent Trigger
  useEffect(() => {
    const handlePointer = (e: PointerEvent) => {
      const x = e.clientX;
      const y = e.clientY;
      const isTopLeft = x < 80 && y < 80;
      const isTopRight = window.innerWidth - x < 80 && y < 80;
      if (!isTopLeft && !isTopRight) return;

      if (gestureTimeout.current) clearTimeout(gestureTimeout.current);
      gestureTimeout.current = setTimeout(() => {
        tapCounts.current = { topLeft: 0, topRight: 0 };
      }, 3000);

      if (isTopLeft) {
        tapCounts.current.topLeft++;
        if (tapCounts.current.topLeft === 3 && !isActiveRef.current) {
          triggerSOS();
        }
      } else if (isTopRight && isActiveRef.current) {
        tapCounts.current.topRight++;
        if (tapCounts.current.topRight === 2) {
          cancelSOS();
        }
      }
    };
    window.addEventListener("pointerdown", handlePointer);
    return () => {
      window.removeEventListener("pointerdown", handlePointer);
      if (gestureTimeout.current) clearTimeout(gestureTimeout.current);
    };
  }, [triggerSOS, cancelSOS]);

  return (
    <div className="min-h-screen bg-black text-white font-sans flex items-center justify-center p-8">
      <div className="max-w-md w-full text-center">
        <div className="mb-8 relative flex justify-center">
          <div
            className={`w-32 h-32 rounded-full flex items-center justify-center border-4 transition-all duration-500 ${
              isActive ? "border-red-600 shadow-[0_0_30px_rgba(232,0,28,0.6)]" : "border-zinc-800"
            }`}
          >
            <span className="text-4xl">{isActive ? "🔴" : "⚪"}</span>
          </div>
          {showConfirmDot && (
            <div className="absolute -top-2 -right-2 w-4 h-4 bg-red-600 rounded-full animate-ping" />
          )}
        </div>

        <h2 className="text-2xl font-black text-red-600 uppercase tracking-tighter mb-2">
          Silent SOS
        </h2>
        <p className="text-zinc-500 text-xs uppercase tracking-widest mb-10">
          {isActive ? "Covert recording in progress..." : "Tap top-left corner 3x to activate"}
        </p>

        {isActive ? (
          <button
            onClick={cancelSOS}
            className="w-full bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 text-white font-bold py-4 rounded-2xl uppercase text-sm tracking-widest transition-all"
          >
            Cancel & Lock Buffer
          </button>
        ) : (
          <button
            onClick={triggerSOS}
            className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-2xl uppercase text-sm tracking-widest transition-all shadow-lg shadow-red-900/20"
          >
            Arm Silent Mode
          </button>
        )}

        <p className="text-[10px] text-zinc-600 mt-8 leading-relaxed">
          Audio is encrypted with AES-256-GCM before being stored locally. GPS coordinates are
          captured silently. No visual indicators appear on screen.
        </p>
      </div>
    </div>
  );
};

export default WitnessSilentSOS;

// WitnessChainOfCustody.tsx
import React, { useState, useEffect, useCallback, useRef } from "react";

// ------------------------------
// SECTION: TYPES & INTERFACES
// ------------------------------
export type ActionType = "viewed" | "exported" | "shared" | "uploaded" | "certificate_generated";

export interface LogEntry {
  id: string;
  recordingId: string;
  action: ActionType;
  timestamp: string;
  deviceId: string;
  userId: string;
  previousHash: string;
  hash: string;
}

// ------------------------------
// SECTION: CRYPTO ENGINE
// ------------------------------

// Stable stringify: sorts keys so hashes don't break if key order changes
const stableStringify = (obj: any): string => {
  return JSON.stringify(obj, Object.keys(obj).sort());
};

const computeSHA256 = async (data: string): Promise<string> => {
  const encoder = new TextEncoder();
  const buffer = await crypto.subtle.digest("SHA-256", encoder.encode(data));
  return Array.from(new Uint8Array(buffer))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
};

// ------------------------------
// SECTION: INDEXEDDB HELPERS
// ------------------------------
const DB_NAME = "WitnessAuditTrail";
const STORE_NAME = "custody_logs";

const openAuditDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, 2);
    req.onupgradeneeded = (e: any) => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        const store = db.createObjectStore(STORE_NAME, { keyPath: "id" });
        store.createIndex("recordingId", "recordingId");
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
};

// ------------------------------
// SECTION: LOGGING & VERIFICATION
// ------------------------------
export const recordCustodyAction = async (
  recordingId: string,
  action: ActionType,
  userId: string,
) => {
  const db = await openAuditDB();
  const tx = db.transaction(STORE_NAME, "readwrite");
  const store = tx.objectStore(STORE_NAME);

  // 1. Get all logs for this recording to find the last hash
  const index = store.index("recordingId");
  const request = index.getAll(recordingId);

  return new Promise<void>((resolve) => {
    request.onsuccess = async () => {
      const logs = request.result.sort(
        (a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime(),
      );
      const previousHash = logs.length > 0 ? logs[logs.length - 1].hash : "00000000000000000000";

      const entryBase = {
        id: crypto.randomUUID(),
        recordingId,
        action,
        timestamp: new Date().toISOString(),
        deviceId: navigator.userAgent.substring(0, 50), // Device footprint
        userId,
        previousHash,
      };

      const hash = await computeSHA256(stableStringify(entryBase));
      const fullEntry: LogEntry = { ...entryBase, hash };

      store.add(fullEntry);
      resolve();
    };
  });
};

// ------------------------------
// SECTION: MAIN UI COMPONENT
// ------------------------------
export default function ChainOfCustodyUI({ recordingId }: { recordingId: string }) {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isVerified, setIsVerified] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchAndVerify = useCallback(async () => {
    setLoading(true);
    const db = await openAuditDB();
    const tx = db.transaction(STORE_NAME, "readonly");
    const store = tx.objectStore(STORE_NAME);
    const request = store.index("recordingId").getAll(recordingId);

    request.onsuccess = async () => {
      const entries: LogEntry[] = request.result.sort(
        (a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime(),
      );

      // Verify the whole chain
      let valid = true;
      let lastHash = "00000000000000000000";

      for (const entry of entries) {
        // A. Check if the link to previous is broken
        if (entry.previousHash !== lastHash) {
          valid = false;
          break;
        }
        // B. Re-calculate hash to ensure data wasn't edited
        const { hash, ...base } = entry;
        const recalculated = await computeSHA256(stableStringify(base));
        if (recalculated !== hash) {
          valid = false;
          break;
        }
        lastHash = hash;
      }

      setLogs(entries);
      setIsVerified(valid);
      setLoading(false);
    };
  }, [recordingId]);

  useEffect(() => {
    fetchAndVerify();
  }, [fetchAndVerify]);

  return (
    <div className="bg-black border border-red-900 rounded-2xl p-6 text-white max-w-2xl mx-auto shadow-2xl">
      <div className="flex justify-between items-center mb-6 border-b border-red-900 pb-4">
        <h2 className="text-xl font-black italic text-red-600">AUDIT LOG / CHAIN OF CUSTODY</h2>
        <button onClick={fetchAndVerify} className="text-[10px] bg-gray-900 px-2 py-1 rounded">
          REFRESH
        </button>
      </div>

      {loading ? (
        <div className="text-center py-10 animate-pulse text-gray-500">
          Verifying Cryptographic Chain...
        </div>
      ) : (
        <>
          <div
            className={`mb-6 p-3 rounded-lg text-center font-bold text-sm ${isVerified ? "bg-green-900/30 text-green-400 border border-green-800" : "bg-red-900/30 text-red-400 border border-red-800"}`}
          >
            {isVerified
              ? "✓ CHAIN VERIFIED: EVIDENCE TAMPER-FREE"
              : "⚠️ CHAIN BREACH: INTEGRITY COMPROMISED"}
          </div>

          <div className="space-y-3 max-h-80 overflow-y-auto pr-2">
            {logs.map((log, i) => (
              <div key={log.id} className="bg-gray-900 p-3 rounded border-l-2 border-red-600">
                <div className="flex justify-between items-start mb-1">
                  <span className="text-xs font-black text-red-500 uppercase">{log.action}</span>
                  <span className="text-[10px] text-gray-500 font-mono">
                    {new Date(log.timestamp).toLocaleString()}
                  </span>
                </div>
                <div className="text-[9px] text-gray-400 truncate">SHA256: {log.hash}</div>
                <div className="text-[9px] text-gray-600">
                  User: {log.userId} • Device: {log.deviceId.substring(0, 30)}...
                </div>
              </div>
            ))}
            {logs.length === 0 && (
              <div className="text-center text-gray-600 text-xs py-10">
                No custody events recorded yet.
              </div>
            )}
          </div>

          <div className="mt-6 flex gap-3">
            <button
              onClick={() => window.print()}
              className="flex-1 bg-red-600 text-white py-3 rounded-xl font-bold text-sm"
            >
              GENERATE AUDIT PDF
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// WitnessDuplicateDetection.tsx
import React, { useState, useEffect, useRef } from "react";

// ------------------------------
// SECTION: TYPES
// ------------------------------
export interface RecordingFingerprint {
  id: string;
  firstFrameHash: string;
  durationMs: number;
  size: number;
  coords: { lat: number; lng: number } | null;
  ts: number;
}

// ------------------------------
// SECTION: CORE ENGINE
// ------------------------------

// Captures a small thumbnail and generates a hash
const generateVisualHash = async (blob: Blob): Promise<{ hash: string; preview: string }> => {
  return new Promise((resolve) => {
    const video = document.createElement("video");
    const canvas = document.createElement("canvas");
    const url = URL.createObjectURL(blob);

    video.muted = true;
    video.playsInline = true;
    video.src = url;

    video.onloadeddata = () => {
      video.currentTime = 0.1; // Seek to 100ms to skip potential black start
    };

    video.onseeked = async () => {
      // Downsample to 160x120 for fast hashing
      canvas.width = 160;
      canvas.height = 120;
      const ctx = canvas.getContext("2d");
      ctx?.drawImage(video, 0, 0, 160, 120);

      const preview = canvas.toDataURL("image/jpeg", 0.5);
      const imageData = ctx?.getImageData(0, 0, 160, 120).data;

      // Hash the pixels
      const hashBuffer = await crypto.subtle.digest("SHA-256", imageData!);
      const hash = Array.from(new Uint8Array(hashBuffer))
        .map((b) => b.toString(16).padStart(2, "0"))
        .join("");

      // Cleanup
      URL.revokeObjectURL(url);
      video.remove();
      resolve({ hash, preview });
    };
  });
};

// Calculates similarity between two recordings (0 to 100)
const calculateSimilarity = (a: RecordingFingerprint, b: RecordingFingerprint): number => {
  let score = 0;

  // 1. Visual Match (50 points)
  if (a.firstFrameHash === b.firstFrameHash) score += 50;

  // 2. Metadata Match (25 points) - Duration within 2 seconds
  if (Math.abs(a.durationMs - b.durationMs) < 2000) score += 25;

  // 3. Location Match (25 points) - Within ~100 meters
  if (a.coords && b.coords) {
    const dist = Math.sqrt(
      Math.pow(a.coords.lat - b.coords.lat, 2) + Math.pow(a.coords.lng - b.coords.lng, 2),
    );
    if (dist < 0.001) score += 25;
  }

  return score;
};

// ------------------------------
// SECTION: MAIN COMPONENT
// ------------------------------
export default function WitnessDuplicateDetection({
  newFile,
  onResolve,
}: {
  newFile: { blob: Blob; duration: number; coords: any };
  onResolve: (action: "both" | "replace" | "discard") => void;
}) {
  const [matchingRec, setMatchingRec] = useState<RecordingFingerprint | null>(null);
  const [previews, setPreviews] = useState({ old: "", current: "" });
  const [similarity, setSimilarity] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const runCheck = async () => {
      // 1. Fingerprint the new file
      const { hash, preview } = await generateVisualHash(newFile.blob);
      const currentFP: RecordingFingerprint = {
        id: "temp",
        firstFrameHash: hash,
        durationMs: newFile.duration,
        size: newFile.blob.size,
        coords: newFile.coords,
        ts: Date.now(),
      };

      // 2. Compare against local DB
      const raw = localStorage.getItem("witness_fingerprints");
      const fingerprints: RecordingFingerprint[] = raw ? JSON.parse(raw) : [];

      let bestMatch: RecordingFingerprint | null = null;
      let highestScore = 0;

      for (const fp of fingerprints) {
        const score = calculateSimilarity(currentFP, fp);
        if (score > 70 && score > highestScore) {
          highestScore = score;
          bestMatch = fp;
        }
      }

      if (bestMatch) {
        setMatchingRec(bestMatch);
        setSimilarity(highestScore);
        setPreviews({ old: localStorage.getItem(`prev_${bestMatch.id}`) || "", current: preview });
        setLoading(false);
      } else {
        // No duplicate - save the fingerprint and move on
        fingerprints.push({ ...currentFP, id: crypto.randomUUID() });
        localStorage.setItem("witness_fingerprints", JSON.stringify(fingerprints.slice(-100))); // Keep last 100
        onResolve("both");
      }
    };

    runCheck();
  }, [newFile]);

  if (loading)
    return (
      <div className="fixed inset-0 bg-black flex items-center justify-center z-[3000]">
        <div className="text-red-600 font-black animate-pulse uppercase tracking-tighter">
          Analyzing for Duplicates...
        </div>
      </div>
    );

  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-md flex items-center justify-center p-6 z-[3000]">
      <div className="bg-gray-900 border border-red-900 rounded-3xl p-8 max-w-lg w-full shadow-2xl">
        <h2 className="text-red-600 font-black italic text-xl mb-2 uppercase">
          Duplicate Detected
        </h2>
        <p className="text-gray-400 text-xs mb-6">
          This recording shares a {similarity}% similarity with an existing file in your vault.
        </p>

        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="text-center">
            <div className="text-[10px] text-gray-500 font-bold mb-2 uppercase">Existing File</div>
            <img
              src={previews.old}
              className="w-full aspect-video object-cover rounded-lg border border-gray-800"
            />
          </div>
