// Global ARIA live region. Use the exported announce() function from anywhere.
import { useEffect, useState } from "react";

let publish: ((msg: string) => void) | null = null;

export function announce(msg: string) {
  publish?.(msg);
}

export function A11yAnnouncer() {
  const [msg, setMsg] = useState("");
  useEffect(() => {
    publish = (m: string) => {
      setMsg("");
      // Two-tick to force AT to re-announce identical text.
      setTimeout(() => setMsg(m), 30);
    };
    return () => {
      publish = null;
    };
  }, []);
  return (
    <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">
      {msg}
    </div>
  );
}

import { useEffect, useState } from "react";
import { Download, X } from "lucide-react";
import { getInstallPrompt, subscribeInstallPrompt, triggerInstall } from "@/lib/pwa";

const DISMISS_KEY = "@Witness_install_dismissed";
const TRIGGER_KEY = "@Witness_first_record_done";

/** Mark that the user just finished their first recording. */
export function markFirstRecording(): void {
  if (typeof window === "undefined") return;
  if (!window.localStorage.getItem(TRIGGER_KEY)) {
    window.localStorage.setItem(TRIGGER_KEY, String(Date.now()));
    window.dispatchEvent(new Event("witness:first-record"));
  }
}

export function InstallPrompt() {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const dismissed = window.localStorage.getItem(DISMISS_KEY);
    if (dismissed) return;

    const evaluate = () => {
      const hasPrompt = !!getInstallPrompt();
      const hasRecorded = !!window.localStorage.getItem(TRIGGER_KEY);
      setVisible(hasPrompt && hasRecorded);
    };

    evaluate();
    const unsub = subscribeInstallPrompt(evaluate);
    window.addEventListener("witness:first-record", evaluate);
    return () => {
      unsub();
      window.removeEventListener("witness:first-record", evaluate);
    };
  }, []);

  if (!visible) return null;

  const dismiss = () => {
    window.localStorage.setItem(DISMISS_KEY, String(Date.now()));
    setVisible(false);
  };

  return (
    <div className="fixed inset-x-0 bottom-4 z-50 mx-auto flex max-w-md items-center gap-3 rounded-2xl border border-border bg-card/95 p-3 shadow-2xl backdrop-blur">
      <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary/15 text-primary">
        <Download className="h-5 w-5" />
      </div>
      <div className="flex-1">
        <p className="text-sm font-semibold text-foreground">Install Witness R.E.P</p>
        <p className="text-xs text-muted-foreground">
          Faster launch, fullscreen camera, works offline.
        </p>
      </div>
      <button
        onClick={async () => {
          const result = await triggerInstall();
          if (result !== "unavailable") setVisible(false);
        }}
        className="rounded-lg bg-primary px-3 py-2 text-xs font-semibold text-primary-foreground"
      >
        Install
      </button>
      <button
        onClick={dismiss}
        aria-label="Dismiss"
        className="rounded-lg p-2 text-muted-foreground hover:text-foreground"
      >
        <X className="h-4 w-4" />
      </button>
    </div>
  );
}

import { useEffect, useState } from "react";
import { AlertTriangle } from "lucide-react";

export interface SyncConflict {
  recordingId: string;
  localTimestamp: number;
  remoteTimestamp: number;
  localTitle?: string;
  remoteTitle?: string;
}

type Listener = (conflict: SyncConflict) => void;
const listeners = new Set<Listener>();

export function reportSyncConflict(c: SyncConflict) {
  listeners.forEach((l) => l(c));
}

export type ConflictResolution = "local" | "remote" | "both";

let resolverFn: ((c: SyncConflict, r: ConflictResolution) => void) | null = null;
export function setSyncConflictResolver(fn: (c: SyncConflict, r: ConflictResolution) => void) {
  resolverFn = fn;
}

export function SyncConflictModal() {
  const [queue, setQueue] = useState<SyncConflict[]>([]);

  useEffect(() => {
    const l: Listener = (c) =>
      setQueue((q) => (q.some((x) => x.recordingId === c.recordingId) ? q : [...q, c]));
    listeners.add(l);
    return () => {
      listeners.delete(l);
    };
  }, []);

  const current = queue[0];
  if (!current) return null;

  const resolve = (r: ConflictResolution) => {
    resolverFn?.(current, r);
    setQueue((q) => q.slice(1));
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/70 p-4">
      <div className="w-full max-w-sm rounded-2xl border border-border bg-card p-5">
        <div className="flex items-center gap-2 text-primary">
          <AlertTriangle className="h-5 w-5" />
          <h2 className="text-base font-bold">Sync conflict</h2>
        </div>
        <p className="mt-2 text-xs text-muted-foreground">
          The same recording exists on two devices with different timestamps. Choose which to keep.
        </p>
        <div className="mt-4 space-y-2 text-xs">
          <div className="rounded-xl border border-border bg-background p-3">
            <p className="font-semibold">This device</p>
            <p className="text-muted-foreground">{current.localTitle ?? current.recordingId}</p>
            <p className="text-muted-foreground">
              {new Date(current.localTimestamp).toLocaleString()}
            </p>
          </div>
          <div className="rounded-xl border border-border bg-background p-3">
            <p className="font-semibold">Other device</p>
            <p className="text-muted-foreground">{current.remoteTitle ?? current.recordingId}</p>
            <p className="text-muted-foreground">
              {new Date(current.remoteTimestamp).toLocaleString()}
            </p>
          </div>
        </div>
        <div className="mt-4 grid grid-cols-3 gap-2">
          <button
            type="button"
            onClick={() => resolve("local")}
            className="h-10 rounded-xl border border-border bg-background text-xs font-semibold active:scale-95"
          >
            Keep local
          </button>
          <button
            type="button"
            onClick={() => resolve("remote")}
            className="h-10 rounded-xl border border-border bg-background text-xs font-semibold active:scale-95"
          >
            Keep remote
          </button>
          <button
            type="button"
            onClick={() => resolve("both")}
            className="h-10 rounded-xl bg-primary text-xs font-semibold text-primary-foreground active:scale-95"
          >
            Keep both
          </button>
        </div>
      </div>
    </div>
  );
}

import { createContext, useCallback, useContext, useMemo, useReducer, type ReactNode } from "react";

type State = { emergency: boolean; emergencyAt: number | null };
type Action = { type: "EMERGENCY_TRIGGER" } | { type: "EMERGENCY_CLEAR" };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "EMERGENCY_TRIGGER":
      return { emergency: true, emergencyAt: Date.now() };
    case "EMERGENCY_CLEAR":
      return { emergency: false, emergencyAt: null };
  }
}

interface Ctx {
  state: State;
  triggerEmergency: () => void;
  clearEmergency: () => void;
}

const WitnessCtx = createContext<Ctx | null>(null);

export function WitnessProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(reducer, { emergency: false, emergencyAt: null });
  const triggerEmergency = useCallback(() => dispatch({ type: "EMERGENCY_TRIGGER" }), []);
  const clearEmergency = useCallback(() => dispatch({ type: "EMERGENCY_CLEAR" }), []);
  const value = useMemo(
    () => ({ state, triggerEmergency, clearEmergency }),
    [state, triggerEmergency, clearEmergency],
  );
  return <WitnessCtx.Provider value={value}>{children}</WitnessCtx.Provider>;
}

export function useWitness(): Ctx {
  const ctx = useContext(WitnessCtx);
  if (!ctx) throw new Error("useWitness must be used inside <WitnessProvider>");
  return ctx;
}

