}

function clusterIcon(L: typeof import("leaflet"), count: number, color: string) {
  return L.divIcon({
    html: `<div class="witness-cluster" style="--pin:${color}"><span>${count}</span></div>`,
    className: "witness-pin-wrap",
    iconSize: [38, 38],
